-- Schema for Domain: revenue | Business: Travel Hospitality | Version: v1_mvm
-- Generated on: 2026-05-08 06:03:13

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `travel_hospitality_ecm`.`revenue` COMMENT 'Authoritative source for pricing strategies, rate plans, yield optimization, and revenue performance. Manages BAR (Best Available Rate), dynamic pricing rules, DRR (Dynamic Rate Rules), rate restrictions, demand forecasting, and competitive benchmarking (STR STAR Report, RGI, MPI, ARI). Tracks ADR, RevPAR, TRevPAR, and GOPPAR metrics. Integrates with IDeaS G3 RMS and Infor EzRMS.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`revenue_rate_plan` (
    `revenue_rate_plan_id` BIGINT COMMENT 'Unique surrogate identifier for each rate plan record in the revenue management system. Primary key for the revenue_rate_plan data product. Role: MASTER_RESOURCE.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Rate plans are frequently created to support specific marketing campaigns (flash sales, seasonal promotions). Campaign managers track which rate plans were deployed per campaign to measure ROI and rev',
    `catering_menu_id` BIGINT COMMENT 'Foreign key linking to event.catering_menu. Business justification: MICE and group rate plans bundle specific catering menus (e.g., all-inclusive day delegate packages). Linking revenue_rate_plan to catering_menu enables package pricing validation, F&B revenue attribu',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Rate plans are distributed through specific channels (OTA, GDS, direct booking). Revenue managers configure which channels can sell which rate plans - core distribution strategy. Replaces denormalized',
    `franchise_agreement_id` BIGINT COMMENT 'Foreign key linking to property.franchise_agreement. Business justification: Franchise agreements define royalty_fee_pct, marketing_fee_pct, and loyalty_fee_pct that directly affect rate plan economics and minimum rate floors. Linking revenue_rate_plan to franchise_agreement e',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Rate plans include F&B benefits (breakfast at specific outlet, dining credits). Required for package fulfillment, benefit tracking, revenue allocation between rooms and F&B departments per USALI stand',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Rate plans must post room revenue to specific GL accounts for revenue recognition and financial statement preparation. Essential for USALI compliance and audit trail.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Rate plans enforce tier-specific eligibility (loyalty_tier_required field exists). Business process: validating member tier qualification for rate plan access at booking time. Essential for tier-based',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: revenue_rate_plan.market_segment_code (STRING) is a denormalized reference to the market segment the rate plan targets. Adding market_segment_id normalizes this to the authoritative market_segment rec',
    `program_config_id` BIGINT COMMENT 'Foreign key linking to loyalty.program_config. Business justification: Rate plans must validate against loyalty program rules (points eligibility, conversion rates, tier requirements). Business process: ensuring rate plan configuration aligns with active loyalty program ',
    `program_id` BIGINT COMMENT 'Foreign key linking to experience.program. Business justification: Rate plans bundle experience programs (e.g., Romance Package rate plan tied to a curated experience program). This FK enables package revenue attribution and program eligibility enforcement at booki',
    `property_id` BIGINT COMMENT 'Reference to the property or hotel at which this rate plan is applicable. Enables property-level rate plan management across a multi-property portfolio. A null value indicates a chain-wide or global rate plan applicable to all properties.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type or room category to which this rate plan applies. A null value indicates the rate plan applies to all room types at the associated property.',
    `touchpoint_id` BIGINT COMMENT 'Foreign key linking to experience.touchpoint. Business justification: Rate plans are designed around guest journey touchpoints (pre-arrival, check-in, in-stay offers) for targeted pricing strategies. Revenue managers create touchpoint-specific rates to optimize conversi',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days prior to arrival that a booking must be made to qualify for this rate plan. Common values are 7, 14, 21, or 30 days for advance purchase promotional rates. A value of 0 indicates no advance purchase requirement.',
    `approved_by` STRING COMMENT 'Name or identifier of the revenue manager or director who approved this rate plan for distribution. Supports SOX financial controls and internal audit requirements for rate authorization governance.',
    `approved_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan was formally approved for activation and distribution. Distinct from created_timestamp; captures the authorization event in the rate plan lifecycle. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `base_rate_amount` DECIMAL(18,2) COMMENT 'The principal nightly room rate amount in the operating currency before any adjustments, taxes, or fees. Represents the rack rate or floor price for this rate plan. Used as the reference value for ADR (Average Daily Rate) and RevPAR (Revenue Per Available Room) calculations. Satisfies MASTER_RESOURCE MEASUREMENT_OR_VALUE category.',
    `booking_window_close_date` DATE COMMENT 'The last date on which new reservations can be made under this rate plan. After this date the rate plan is closed to new bookings even if the stay dates fall within the effective period.',
    `booking_window_open_date` DATE COMMENT 'The earliest date on which reservations can be made under this rate plan. Used to control promotional rate availability windows and prevent premature booking of seasonal or event-driven rates.',
    `cancellation_policy_code` STRING COMMENT 'Code referencing the cancellation and penalty policy associated with this rate plan (e.g., FLEX24H, NRR_NOREF, 48H_PENALTY). Determines guest refund eligibility and penalty charges upon cancellation. Critical for NRR (Non-Refundable Rate) and advance purchase rate plans.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `commission_pct` DECIMAL(18,2) COMMENT 'The percentage of the room rate payable as commission to the booking agent or OTA when is_commissionable is true. Expressed as a percentage (e.g., 10.00 for 10%). Null when is_commissionable is false.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan record was first created in the source system. Used for audit trail, data lineage, and compliance reporting. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the base_rate_amount and all monetary fields on this rate plan are denominated (e.g., USD, EUR, GBP). Required for multi-currency property portfolios.. Valid values are `^[A-Z]{3}$`',
    `discount_pct` DECIMAL(18,2) COMMENT 'Percentage discount applied to the BAR (Best Available Rate) or rack rate to derive this rate plans selling price. Used for corporate negotiated rates, loyalty member rates, and promotional rates. A value of 0 indicates no discount from the reference rate.',
    `drr_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is subject to DRR (Dynamic Rate Rule) adjustments by the revenue management system. When true, IDeaS G3 RMS or Infor EzRMS may automatically adjust the rate based on demand forecasts, occupancy levels, and competitive benchmarking.',
    `effective_date` DATE COMMENT 'The calendar date from which this rate plan becomes active and bookable. Used by IDeaS G3 RMS and Sabre SynXis CRS to control rate availability windows. Satisfies MASTER_AGREEMENT EFFECTIVE_FROM category.',
    `expiry_date` DATE COMMENT 'The calendar date after which this rate plan is no longer available for new bookings. Null indicates an open-ended rate plan with no defined end date. Satisfies MASTER_AGREEMENT EFFECTIVE_UNTIL category.',
    `gds_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is distributed through GDS (Global Distribution System) channels such as Amadeus, Sabre, Travelport. Controls rate visibility to travel agents using GDS booking tools.',
    `is_commissionable` BOOLEAN COMMENT 'Indicates whether a travel agent or OTA (Online Travel Agency) commission is payable on bookings made under this rate plan. Drives commission accrual and payment processing in SAP S/4HANA AP.',
    `is_lra_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan carries LRA (Last Room Availability) obligation, meaning the contracted rate must be honored even when only the last room in a category is available. Applicable to corporate negotiated rate contracts.',
    `is_refundable` BOOLEAN COMMENT 'Indicates whether bookings under this rate plan are eligible for a full refund upon cancellation within the policy window. False for NRR (Non-Refundable Rate) plans; true for flexible BAR (Best Available Rate) plans.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'The timestamp when this rate plan record was most recently updated in the source system. Used to detect changes for incremental ETL processing and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `loyalty_points_eligible` BOOLEAN COMMENT 'Indicates whether stays booked under this rate plan qualify for loyalty program points accrual. Wholesale, opaque, and certain promotional rates are typically ineligible for points earning.',
    `loyalty_tier_required` STRING COMMENT 'Minimum loyalty program membership tier required to access this rate plan. A value of none indicates the rate is open to all guests regardless of loyalty status. Used to gate exclusive member rates.. Valid values are `none|silver|gold|platinum|diamond`',
    `max_los` STRING COMMENT 'Maximum number of nights permitted under this rate plan. Used to prevent extended stays at promotional or deeply discounted rates. A null value indicates no maximum stay restriction.',
    `meal_plan_type` STRING COMMENT 'Indicates the F&B (Food and Beverage) inclusions bundled with this rate plan. Room only includes no meals; bed and breakfast includes morning meal; half board includes breakfast and dinner; full board includes all three meals; all-inclusive covers meals, beverages, and selected activities.. Valid values are `room_only|bed_breakfast|half_board|full_board|all_inclusive`',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must book to qualify for this rate plan. A LOS (Length of Stay) restriction used in yield optimization to drive longer stays during high-demand periods. A value of 1 indicates no minimum stay restriction.',
    `ota_eligible` BOOLEAN COMMENT 'Indicates whether this rate plan is distributed through OTA (Online Travel Agency) channels such as Booking.com, Expedia, or Agoda. Controls rate visibility on third-party booking platforms.',
    `rate_category` STRING COMMENT 'Secondary classification grouping rate plans by the market segment or distribution channel they serve. Public rates are available to all guests; negotiated rates are contracted with specific accounts; wholesale rates are sold through tour operators; group rates apply to block bookings; loyalty rates are exclusive to program members; employee rates are internal staff benefits.. Valid values are `public|negotiated|wholesale|group|loyalty|employee`',
    `rate_ceiling_amount` DECIMAL(18,2) COMMENT 'The maximum rate above which this rate plan cannot be sold, used to cap pricing during peak demand periods for contracted or promotional rates. Null indicates no ceiling constraint.',
    `rate_floor_amount` DECIMAL(18,2) COMMENT 'The minimum rate below which this rate plan cannot be sold, regardless of dynamic pricing adjustments. Protects rate integrity and brand positioning. Used by IDeaS G3 RMS as a hard constraint in yield optimization algorithms.',
    `rate_level` STRING COMMENT 'Indicates the organizational scope at which this rate plan is defined and managed. Property-level plans apply to a single hotel; brand-level plans apply across a brand portfolio; chain-level plans apply across the entire company; global plans may span international markets.. Valid values are `property|brand|chain|global`',
    `rate_plan_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the rate plan across systems (e.g., BAR, CORP001, PKG-SPA). Used as the business key in IDeaS G3 RMS, Sabre SynXis CRS, and Oracle OPERA PMS for rate plan lookup and distribution. Satisfies MASTER_RESOURCE BUSINESS_IDENTIFIER category.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_plan_description` STRING COMMENT 'Free-text description of the rate plans terms, inclusions, and conditions as displayed to guests and booking agents. Includes details on what is included in the rate, any special conditions, and marketing messaging.',
    `rate_plan_name` STRING COMMENT 'Human-readable name of the rate plan displayed to guests and revenue managers (e.g., Best Available Rate, AAA Member Rate, Advance Purchase 21-Day). Satisfies MASTER_RESOURCE IDENTITY_LABEL category.',
    `rate_plan_type` STRING COMMENT 'Classification of the rate plan by its commercial structure. BAR (Best Available Rate) is the publicly available flexible rate; LRA (Last Room Availability) guarantees availability to contracted accounts; NRR (Non-Refundable Rate) carries no cancellation flexibility; corporate rates are negotiated with companies; package rates bundle room with ancillary services; promotional rates are time-limited offers. Satisfies MASTER_RESOURCE CLASSIFICATION_OR_TYPE category.. Valid values are `BAR|LRA|NRR|corporate|package|promotional`',
    `rate_status` STRING COMMENT 'Current lifecycle state of the rate plan. Active plans are available for booking; inactive plans are temporarily disabled; draft plans are under configuration; suspended plans are paused due to yield or compliance review; archived plans are retired and no longer bookable. Satisfies MASTER_RESOURCE LIFECYCLE_STATUS category.. Valid values are `active|inactive|draft|suspended|archived`',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this rate plan record was sourced. Enables data lineage tracking and conflict resolution when the same rate plan exists in multiple systems.. Valid values are `IDEASG3|SYNXIS|OPERA|EZRMS`',
    `source_system_rate_reference` STRING COMMENT 'The native identifier of this rate plan in the originating operational system (IDeaS G3 RMS, Sabre SynXis CRS, or Oracle OPERA PMS). Enables bidirectional traceability between the lakehouse Silver layer and the system of record.',
    `stay_date_restriction` STRING COMMENT 'Defines any day-of-week or date-specific restrictions on when stays under this rate plan are permitted. Weekday-only and weekend-only restrictions are common for corporate and leisure rates respectively; blackout dates exclude specific high-demand periods.. Valid values are `none|weekday_only|weekend_only|blackout_dates|specific_dates`',
    `tax_inclusive` BOOLEAN COMMENT 'Indicates whether the base_rate_amount includes applicable taxes (VAT, occupancy tax, city tax). True for tax-inclusive markets; false for markets where taxes are added at checkout. Critical for accurate revenue recognition under USALI and IFRS/GAAP.',
    CONSTRAINT pk_revenue_rate_plan PRIMARY KEY(`revenue_rate_plan_id`)
) COMMENT 'Master catalog of all rate plans available across properties, including BAR (Best Available Rate), LRA (Last Room Availability), NRR (Non-Refundable Rate), corporate negotiated rates, package rates, and promotional rates. Defines rate structure, cancellation policy, meal plan inclusions, booking conditions, and distribution eligibility. Sourced from IDeaS G3 RMS and Sabre SynXis CRS. This is the SSOT for rate plan definitions.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`rate_restriction` (
    `rate_restriction_id` BIGINT COMMENT 'Unique surrogate identifier for each rate restriction record in the revenue management system. Primary key for the rate_restriction data product in the Databricks Silver Layer.',
    `cancellation_policy_id` BIGINT COMMENT 'Foreign key linking to reservation.cancellation_policy. Business justification: Revenue managers apply cancellation policy restrictions as part of yield management strategy. Rate restrictions must enforce specific cancellation terms (non-refundable, free cancellation windows) to ',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Restrictions (stop-sell, min LOS, CTA/CTD) are applied per distribution channel. Revenue managers close channels selectively based on demand - essential inventory control operation. Enables channel-sp',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Foreign key linking to revenue.dynamic_rate_rule. Business justification: rate_restriction.rms_recommendation_flag (BOOLEAN) indicates that a restriction was recommended by the RMS (IDeaS G3 or Infor EzRMS). Dynamic rate rules in the RMS trigger rate restrictions (e.g., min',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Revenue managers apply specific rate restrictions (min LOS, CTA/CTD, hurdle rates) when large event bookings create displacement risk. Essential for RMS restriction management around group blocks and ',
    `event_group_block_id` BIGINT COMMENT 'Foreign key linking to event.event_group_block. Business justification: Rate restrictions (minimum LOS, closed-to-arrival, stop-sell) are frequently applied in direct response to active group blocks to protect transient revenue. Linking rate_restriction to event_group_blo',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Rate restrictions include an is_loyalty_exempt flag; revenue managers must reference the specific loyalty promotion that triggers the exemption. Named process: restriction exemption management for loy',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Rate restrictions can be tier-exempt (e.g., Platinum members bypass minimum LOS restrictions). The is_loyalty_exempt flag exists but no tier FK identifies which tier is exempt. Named process: tier-bas',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Rate restrictions can be scoped to market segments (e.g., restrict Leisure segment on peak dates). rate_restriction has market_segment_code (STRING) which should be normalized to FK. N rate_restrictio',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel/resort) to which this rate restriction applies. Enables property-level yield optimization and restriction management across the portfolio.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan to which this restriction applies. Links to the rate plan master in the CRS/RMS (e.g., BAR, LRA, NRR, DRR). A restriction may apply to one or multiple rate plans; this field captures the primary rate plan association.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type to which this restriction applies. When null, the restriction applies to all room types under the associated rate plan. Enables granular inventory control by room category.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Rate restrictions (CTA, CTD, min LOS) are applied based on seasonal demand periods. rate_restriction.season_code is a denormalized reference to seasonal_calendar. A direct FK enables restriction audit',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Rate restrictions are operational implementations of the revenue strategy (e.g., minimum LOS restrictions during high-demand periods as defined in the strategy). Adding strategy_id links each restrict',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days prior to arrival that a booking must be made to qualify for this rate plan. Supports NRR (Non-Refundable Rate) and advance purchase yield strategies. Null when restriction type is not ADVANCE_PURCHASE.',
    `applied_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction was activated and distributed to connected channels (CRS, GDS, OTA). Represents the principal business event time â€” when the restriction became operationally effective in the distribution ecosystem. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `created_by_user` STRING COMMENT 'Username or employee identifier of the revenue manager or system process that created this rate restriction record. Supports SOX financial controls audit trail and accountability for yield management decisions.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction record was first created in the source system. Used for audit trail, data lineage, and SLA compliance tracking. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the hurdle_rate_amount and any monetary thresholds defined in this restriction (e.g., USD, EUR, GBP). Ensures consistent financial reporting per USALI standards.. Valid values are `^[A-Z]{3}$`',
    `days_of_week_mask` STRING COMMENT '7-character binary string indicating which days of the week the restriction applies, ordered Monday through Sunday (e.g., 1111100 = Monâ€“Fri only, 0000011 = Satâ€“Sun only). Enables day-of-week yield strategies such as weekend minimum stay requirements.. Valid values are `^[01]{7}$`',
    `demand_forecast_level` STRING COMMENT 'Demand forecast classification at the time this restriction was created or last updated, as determined by the RMS (IDeaS G3 or Infor EzRMS). Provides context for why the restriction was applied and supports post-hoc yield strategy analysis.. Valid values are `low|medium|high|peak|sold_out`',
    `distribution_status` STRING COMMENT 'Indicates the current distribution state of this restriction across connected channels via Sabre SynXis CRS. pending = queued for distribution; distributed = successfully pushed to all channels; failed = distribution error; partial = distributed to some but not all channels.. Valid values are `pending|distributed|failed|partial`',
    `effective_date` DATE COMMENT 'The calendar date from which this rate restriction becomes active and enforceable. Corresponds to the stay date (not booking date) unless the restriction type is ADVANCE_PURCHASE. Formatted as yyyy-MM-dd per model conventions.',
    `expiry_date` DATE COMMENT 'The last calendar date on which this rate restriction is enforceable (inclusive). Null indicates an open-ended restriction with no defined end. Formatted as yyyy-MM-dd per model conventions.',
    `hurdle_rate_amount` DECIMAL(18,2) COMMENT 'Minimum acceptable rate (in the propertys base currency) below which a booking will be rejected for this rate plan on the restricted date(s). A key RMS yield control used to protect ADR during high-demand periods. Null when restriction type is not HURDLE_RATE.',
    `is_blackout` BOOLEAN COMMENT 'Indicates whether the effective date range is designated as a blackout period, during which the rate plan is completely closed to new bookings. Commonly applied during peak demand events, holidays, or sold-out periods.',
    `is_cta` BOOLEAN COMMENT 'Indicates whether arrivals are blocked on the effective date(s) for this rate plan and room type. When True, guests cannot check in on the restricted date, preventing short-stay bookings that fragment inventory during high-demand periods.',
    `is_ctd` BOOLEAN COMMENT 'Indicates whether departures are blocked on the effective date(s) for this rate plan and room type. When True, guests cannot check out on the restricted date, used to extend stays through high-demand nights and maximize occupancy continuity.',
    `is_loyalty_exempt` BOOLEAN COMMENT 'Indicates whether members of the hotels loyalty program are exempt from this restriction (e.g., LRA â€” Last Room Availability guarantee for elite members). Supports loyalty program administration and member benefit fulfillment.',
    `last_distributed_timestamp` TIMESTAMP COMMENT 'The date and time when this restriction was last successfully distributed to external channels (OTA, GDS) via Sabre SynXis CRS. Used to monitor distribution latency and SLA compliance for rate parity management.',
    `max_advance_purchase_days` STRING COMMENT 'Maximum number of days prior to arrival within which a booking must be made to qualify for this rate plan. Defines the booking window ceiling for advance purchase restrictions, preventing bookings made too far in advance at promotional rates.',
    `max_los` STRING COMMENT 'Maximum number of nights a guest is permitted to stay under this rate plan on the restricted date(s). Used to prevent long-stay bookings at discounted rates during high-demand periods. Null when restriction type is not MAX_LOS.',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must stay to be eligible to book under this rate plan on the restricted date(s). A core yield optimization lever in revenue management. Null when restriction type is not MIN_LOS.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes or context provided by the revenue manager regarding this restriction. May include references to specific events, competitive intelligence, or strategy rationale not captured in structured fields.',
    `override_allowed` BOOLEAN COMMENT 'Indicates whether a revenue manager or front desk supervisor is permitted to manually override this restriction for individual bookings. When False, the restriction is hard-enforced and cannot be bypassed in the PMS or CRS.',
    `override_authorization_level` STRING COMMENT 'Minimum staff authorization level required to override this restriction when override_allowed is True. Ensures appropriate governance over yield control exceptions. Null when override_allowed is False.. Valid values are `supervisor|manager|director|revenue_manager`',
    `priority_rank` STRING COMMENT 'Numeric priority rank used to resolve conflicts when multiple restrictions apply to the same rate plan, room type, and date. Lower values indicate higher priority. Ensures deterministic restriction enforcement when overlapping rules exist in the RMS.',
    `restriction_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this rate restriction rule as defined in IDeaS G3 RMS or Sabre SynXis CRS. Used for cross-system reconciliation and distribution to OTA and GDS channels.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `restriction_name` STRING COMMENT 'Human-readable name describing the rate restriction rule (e.g., Weekend Min 2-Night Stay, Holiday CTA Block). Used by revenue managers and front desk staff to identify restrictions in PMS and RMS interfaces.',
    `restriction_reason` STRING COMMENT 'Free-text or coded explanation for why this restriction was applied (e.g., Peak demand event, Holiday blackout, Group block protection, RMS auto-recommendation). Supports revenue strategy documentation and post-stay performance analysis.',
    `restriction_scope` STRING COMMENT 'Defines the level at which this restriction is applied: property = entire property; room_type = specific room category; rate_plan = specific rate plan only; channel = specific distribution channel (OTA, GDS, direct). Determines how broadly the restriction is enforced across inventory.. Valid values are `property|room_type|rate_plan|channel`',
    `restriction_status` STRING COMMENT 'Current lifecycle state of the rate restriction record. active = currently enforced; inactive = disabled but retained for history; pending = scheduled but not yet effective; expired = past end date; overridden = manually superseded by a revenue manager.. Valid values are `active|inactive|pending|expired|overridden`',
    `restriction_type` STRING COMMENT 'Classification of the restriction mechanism applied. MIN_LOS = Minimum Length of Stay; MAX_LOS = Maximum Length of Stay; CTA = Closed to Arrival; CTD = Closed to Departure; ADVANCE_PURCHASE = minimum days before arrival required to book; BLACKOUT = date fully closed to booking; HURDLE_RATE = minimum acceptable rate threshold. [ENUM-REF-CANDIDATE: MIN_LOS|MAX_LOS|CTA|CTD|ADVANCE_PURCHASE|BLACKOUT|HURDLE_RATE â€” promote to reference product]',
    `rms_recommendation_flag` BOOLEAN COMMENT 'Indicates whether this restriction was system-recommended by the RMS (True) or manually created by a revenue manager (False). Enables analysis of RMS automation adoption rates and comparison of system vs. human yield decisions.',
    `source_system` STRING COMMENT 'Identifies the operational system of record that originated this rate restriction record. Supports data lineage tracking and reconciliation across IDeaS G3 RMS, Infor EzRMS, Oracle OPERA PMS, and Sabre SynXis CRS.. Valid values are `IDEAS_G3|INFOR_EZRMS|OPERA_PMS|SYNXIS_CRS|MANUAL`',
    `source_system_restriction_reference` STRING COMMENT 'The native identifier of this restriction record in the originating operational system (IDeaS G3 RMS, Sabre SynXis CRS, etc.). Enables traceability and reconciliation between the lakehouse Silver Layer and the system of record.',
    `updated_by_user` STRING COMMENT 'Username or employee identifier of the revenue manager or system process that last modified this rate restriction record. Supports audit trail and governance of yield management changes.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this rate restriction record was last modified in the source system. Tracks the most recent change for audit and reconciliation purposes. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_rate_restriction PRIMARY KEY(`rate_restriction_id`)
) COMMENT 'Operational records of rate restrictions applied to rate plans and room types, including minimum LOS (Length of Stay), maximum LOS, closed-to-arrival (CTA), closed-to-departure (CTD), advance purchase requirements, and blackout dates. Managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. Drives yield optimization by controlling which rates are bookable under specific conditions.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`dynamic_rate_rule` (
    `dynamic_rate_rule_id` BIGINT COMMENT 'Unique surrogate identifier for a Dynamic Rate Rule (DRR) record in the revenue management system. Primary key for this entity.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Dynamic pricing rules are often triggered by marketing campaigns (e.g., increase rates during high-awareness periods). Revenue managers need campaign context to evaluate rule performance and campaign-',
    `competitive_set_id` BIGINT COMMENT 'Identifier of the competitive set (comp set) used as the benchmark for competitive-based Dynamic Rate Rules. References the STR STAR Report comp set configuration in Infor EzRMS for RGI, MPI, and ARI-driven pricing decisions.',
    `demand_forecast_id` BIGINT COMMENT 'Identifier of the demand forecast record from IDeaS G3 RMS or Infor EzRMS that this forecast-based Dynamic Rate Rule references for its trigger evaluation.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Dynamic pricing rules target specific channels differently (e.g., OTA rates adjust based on commission costs, direct channel gets best rate). RMS systems apply channel-specific rate optimization strat',
    `segment_id` BIGINT COMMENT 'Foreign key linking to guest.segment. Business justification: Dynamic pricing rules target specific guest segments for personalized rate adjustments. Revenue management systems apply segment-specific pricing logic (e.g., loyalty tier discounts, corporate negotia',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Dynamic pricing adjustments must post to specific GL accounts for audit trail, revenue variance tracking, and SOX compliance in automated pricing systems.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Dynamic pricing rules adjust rates based on member tier for personalized revenue optimization. Business process: applying tier-specific rate adjustments in revenue management systems to reward high-va',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Dynamic rate rules can be scoped to specific market segments. dynamic_rate_rule has market_segment_code (STRING) which should be normalized to FK. N DRR records â†’ 1 market_segment. Removes redundant m',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Dynamic pricing rules monitor outlet occupancy for total revenue optimization (restaurant full = adjust room+dining packages). Required for integrated revenue management systems that optimize property',
    `property_id` BIGINT COMMENT 'Identifier of the hotel or resort property to which this Dynamic Rate Rule applies. Links to the property master record in Oracle OPERA PMS.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Identifier of the rate plan (e.g., BAR, LRA, NRR) to which this Dynamic Rate Rule applies. A null value indicates the rule applies across all eligible rate plans for the property.',
    `room_type_id` BIGINT COMMENT 'Identifier of the specific room type (e.g., standard king, deluxe suite) to which this Dynamic Rate Rule applies. A null value indicates the rule applies across all room types at the property.',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Dynamic rate rules implement the automated pricing adjustments defined within the revenue strategy. Adding strategy_id links each DRR to the governing strategy, enabling revenue managers to audit whic',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Dynamic rate rules are triggered by or aligned with loyalty promotions (e.g., rate floor adjustments during a tier-challenge promotion). Named process: promotion-triggered dynamic pricing rule configu',
    `adjustment_direction` STRING COMMENT 'Indicates whether the Dynamic Rate Rule increases or decreases the rate when triggered. Provides explicit directional intent separate from the sign of adjustment_value to prevent ambiguity in RMS configuration.. Valid values are `increase|decrease`',
    `adjustment_type` STRING COMMENT 'Method by which the Dynamic Rate Rule adjusts the published rate when triggered. Percentage applies a relative increase or decrease to the current rate; absolute_amount adds or subtracts a fixed currency value; bar_offset moves the rate a fixed amount above or below the Best Available Rate (BAR); bar_multiplier applies a multiplier to the BAR.. Valid values are `percentage|absolute_amount|bar_offset|bar_multiplier`',
    `adjustment_value` DECIMAL(18,2) COMMENT 'The magnitude of the rate adjustment applied when the Dynamic Rate Rule is triggered. Interpreted according to adjustment_type: a value of 0.10 with type percentage means a 10% rate increase; a value of 25.00 with type absolute_amount means a $25 rate increase; a value of -15.00 with type bar_offset means $15 below BAR.',
    `advance_booking_max_days` STRING COMMENT 'Maximum number of days in advance of the arrival date within which a booking must be made for this Dynamic Rate Rule to be eligible to apply. Null indicates no upper advance booking restriction.',
    `advance_booking_min_days` STRING COMMENT 'Minimum number of days in advance of the arrival date that a booking must be made for this Dynamic Rate Rule to be eligible to apply. Supports advance purchase pricing strategies.',
    `approval_status` STRING COMMENT 'Workflow approval state of the Dynamic Rate Rule indicating whether it has been reviewed and authorized by a revenue manager before activation. Supports SOX-compliant pricing governance controls.. Valid values are `pending_approval|approved|rejected|auto_approved`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the revenue manager or director who approved this Dynamic Rate Rule for activation. Required for SOX financial controls audit trail on pricing decisions.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule was approved for activation by the authorized revenue manager. Part of the pricing governance audit trail required under SOX financial controls.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule record was first created in the system. Part of the standard audit trail for pricing configuration governance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the property in which rate floor, ceiling, and absolute adjustment values are denominated (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `days_of_week_mask` STRING COMMENT 'Seven-character binary string (positions 1â€“7 = Monâ€“Sun) indicating which days of the week this Dynamic Rate Rule is eligible to fire. A value of 1111100 means Monday through Friday only. Enables day-of-week yield optimization strategies.. Valid values are `^[01]{7}$`',
    `effective_from` DATE COMMENT 'The calendar date from which this Dynamic Rate Rule becomes active and eligible to trigger automated pricing adjustments in the RMS. Aligns with the stay date range for yield optimization.',
    `effective_until` DATE COMMENT 'The calendar date on which this Dynamic Rate Rule expires and ceases to trigger automated pricing adjustments. Null indicates an open-ended rule with no defined expiry.',
    `is_stackable` BOOLEAN COMMENT 'Indicates whether this Dynamic Rate Rule can be combined (stacked) with other active rules for the same stay date, room type, and rate plan. When False, this rule takes exclusive precedence based on rule_priority and no other rules are applied concurrently.',
    `last_triggered_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule was most recently evaluated as true and triggered an automated pricing adjustment in the RMS. Used by revenue managers to monitor rule activity and effectiveness.',
    `los_max_nights` STRING COMMENT 'Maximum Length of Stay (LOS) restriction in nights beyond which this Dynamic Rate Rule does not apply. Null indicates no upper LOS restriction.',
    `los_min_nights` STRING COMMENT 'Minimum Length of Stay (LOS) restriction in nights that must be satisfied for this Dynamic Rate Rule to apply. Used in LOS-based yield optimization to drive longer stays during high-demand periods.',
    `max_rate_ceiling` DECIMAL(18,2) COMMENT 'The highest permissible rate (in property currency) that this Dynamic Rate Rule may produce after adjustment. Acts as a pricing guardrail to prevent rates from exceeding the propertys maximum acceptable rate cap. Sensitive pricing strategy data.',
    `min_rate_floor` DECIMAL(18,2) COMMENT 'The lowest permissible rate (in property currency) that this Dynamic Rate Rule may produce after adjustment. Acts as a pricing guardrail to prevent rates from falling below the propertys minimum acceptable ADR threshold. Sensitive pricing strategy data.',
    `pickup_window_days` STRING COMMENT 'Number of days in the booking pickup window used to evaluate pickup velocity for pickup-based Dynamic Rate Rules. For example, a value of 7 means the rule evaluates rooms booked in the last 7 days.',
    `rms_rule_reference_code` STRING COMMENT 'Native rule identifier assigned by the source Revenue Management System (IDeaS G3 RMS or Infor EzRMS) for this Dynamic Rate Rule. Used for system-of-record traceability and reconciliation between the lakehouse Silver layer and the operational RMS.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the Dynamic Rate Rule within the Revenue Management System (RMS). Used for cross-system reference between IDeaS G3 RMS, Infor EzRMS, and Sabre SynXis CRS.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `rule_description` STRING COMMENT 'Detailed narrative description of the Dynamic Rate Rules business purpose, pricing logic, and intended yield optimization outcome.',
    `rule_name` STRING COMMENT 'Human-readable name describing the Dynamic Rate Rule, used by revenue managers to identify and manage pricing strategies within the RMS dashboard.',
    `rule_priority` STRING COMMENT 'Numeric priority ranking that determines the order of evaluation when multiple Dynamic Rate Rules are eligible to fire simultaneously for the same property, room type, and rate plan. Lower numeric values indicate higher priority (e.g., 1 = highest priority).',
    `rule_status` STRING COMMENT 'Current lifecycle state of the Dynamic Rate Rule governing whether it is eligible to trigger automated pricing adjustments. Active rules are evaluated by the RMS engine; draft rules are under configuration; suspended rules are temporarily disabled; archived rules are retained for historical audit.. Valid values are `active|inactive|draft|suspended|archived`',
    `rule_type` STRING COMMENT 'Classification of the Dynamic Rate Rule by the trigger mechanism driving automated pricing adjustments. Occupancy-based rules fire on OCC thresholds; pickup-based on booking velocity; competitive-based on RGI/ARI/MPI benchmarks from STR STAR Report; event-based on MICE or local demand events; LOS-based on Length of Stay (LOS) restrictions; forecast-based on RMS demand forecasts. [ENUM-REF-CANDIDATE: occupancy_based|pickup_based|competitive_based|event_based|los_based|forecast_based â€” promote to reference product]. Valid values are `occupancy_based|pickup_based|competitive_based|event_based|los_based|forecast_based`',
    `source_system` STRING COMMENT 'Operational system of record from which this Dynamic Rate Rule was originated or last synchronized. Supports data lineage tracking across the revenue management technology stack.. Valid values are `IDeaS_G3_RMS|Infor_EzRMS|Oracle_OPERA_PMS|Manual`',
    `trigger_count` STRING COMMENT 'Cumulative number of times this Dynamic Rate Rule has been triggered and applied a pricing adjustment since its activation date. Used to assess rule utilization and yield optimization effectiveness.',
    `trigger_threshold_operator` STRING COMMENT 'Comparison operator applied to the trigger threshold value to determine whether the rule condition is met. For example, greater_than with a threshold of 0.80 means the rule fires when OCC exceeds 80%.. Valid values are `greater_than|less_than|greater_than_or_equal|less_than_or_equal|equal`',
    `trigger_threshold_unit` STRING COMMENT 'Unit of measure for the trigger threshold value. Percentage applies to OCC-based rules; room_count applies to pickup-based rules; index_value applies to competitive benchmarking rules (RGI, MPI, ARI); currency_amount applies to ADR-based triggers; nights applies to LOS-based rules.. Valid values are `percentage|room_count|index_value|currency_amount|nights`',
    `trigger_threshold_value` DECIMAL(18,2) COMMENT 'The numeric threshold at which this Dynamic Rate Rule fires. For occupancy-based rules, this is the OCC percentage (e.g., 0.80 = 80%). For pickup-based rules, this is the number of rooms picked up within the pickup window. For competitive-based rules, this is the RGI or ARI index value.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this Dynamic Rate Rule record was most recently modified. Used for change data capture (CDC) in the Databricks Lakehouse Silver layer ETL pipeline.',
    `version_number` STRING COMMENT 'Incremental version counter tracking the number of times this Dynamic Rate Rule configuration has been modified. Supports audit trail and change management for pricing strategy governance.',
    CONSTRAINT pk_dynamic_rate_rule PRIMARY KEY(`dynamic_rate_rule_id`)
) COMMENT 'DRR (Dynamic Rate Rule) definitions governing automated pricing adjustments in IDeaS G3 RMS and Infor EzRMS. Captures rule type (occupancy-based, pickup-based, competitive-based, event-based), trigger thresholds, adjustment type (percentage, absolute, BAR offset), applicable room types, applicable rate plans, effective date ranges, and rule priority. Core mechanism for yield optimization and dynamic pricing strategy.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`pricing_override` (
    `pricing_override_id` BIGINT COMMENT 'Unique surrogate identifier for each manual pricing override record in the revenue management system. Primary key for the pricing_override data product.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Pricing overrides are sometimes tier-specific (e.g., a special rate floor applicable only to Platinum members). Named process: tier-specific pricing override authorization and audit. Revenue managers ',
    `banquet_event_order_id` BIGINT COMMENT 'Foreign key linking to fnb.banquet_event_order. Business justification: Manual rate overrides for groups tied to F&B minimum spend commitments from banquet events. Required for group contract evaluation, displacement analysis that includes total property spend, not just r',
    `member_id` BIGINT COMMENT 'Foreign key linking to loyalty.member. Business justification: Pricing overrides are granted for specific high-value loyalty members (VIP rate requests). Revenue managers need to audit which member received a below-floor override. Named process: member-specific p',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Manual rate overrides are sometimes applied to honor campaign promises or fix campaign-related pricing errors. Tracking the campaign context is essential for audit, reconciliation, and campaign cost a',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Manual rate overrides often apply to specific channels (e.g., override OTA rate due to parity issue, adjust GDS rate for corporate segment). Revenue managers need to track which channel triggered over',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Reference to the Dynamic Rate Rule (DRR) that was in effect and being superseded by this manual override. Enables analysis of how frequently manual overrides conflict with automated DRR logic and supports RMS rule tuning.',
    `event_booking_id` BIGINT COMMENT 'Reference to a specific event, conference, or MICE (Meetings, Incentives, Conferences, Exhibitions) event that triggered the pricing override when override_reason_code is event_demand. Links to the event master record in Delphi by Amadeus.',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Manual rate overrides require GL posting for revenue variance tracking, management override reporting, and SOX control documentation in financial audits.',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Manual pricing overrides are often segment-specific (e.g., overriding the corporate rate for a specific segment during a high-demand period). Adding market_segment_id links each override to the market',
    `property_id` BIGINT COMMENT 'Reference to the hotel or resort property for which the pricing override was applied. Links to the property master record in Oracle OPERA PMS.',
    `reservation_group_block_id` BIGINT COMMENT 'Reference to the group room block associated with this pricing override when override_reason_code is group_wash. Links to the group block record in Oracle OPERA PMS or Delphi by Amadeus for group displacement analysis.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan (e.g., BAR, LRA, NRR, corporate, group) against which the pricing override is applied. Sourced from IDeaS G3 RMS and Sabre SynXis CRS rate plan catalog.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Suite, Standard Double) to which the pricing override applies. Sourced from Oracle OPERA PMS room type configuration.',
    `service_recovery_action_id` BIGINT COMMENT 'Foreign key linking to experience.service_recovery_action. Business justification: Pricing overrides issued as service recovery compensation must reference the originating service_recovery_action for audit trail and finance reconciliation. Revenue managers and guest experience teams',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Pricing overrides represent deviations from system-generated rates. Linking each override to the active revenue strategy enables measurement of override frequency and magnitude relative to strategy ta',
    `approval_required` BOOLEAN COMMENT 'Indicates whether this pricing override required formal approval before activation, based on the rate variance threshold or property-level governance policy. True = approval workflow triggered; False = auto-approved within tolerance.',
    `approval_threshold_pct` DECIMAL(18,2) COMMENT 'The rate variance percentage threshold (as a decimal, e.g., 0.2000 = 20%) that triggered the approval requirement for this override. Captures the governance rule in effect at the time of submission for audit purposes.',
    `approved_timestamp` TIMESTAMP COMMENT 'The date and time when the pricing override was formally approved by the authorizing revenue manager or director. Null if override is still pending or was reversed without approval.',
    `channel_restriction` STRING COMMENT 'Specifies which distribution channels the overridden rate is published to. all_channels = no restriction; direct_only = hotel direct and brand website only; ota_excluded = all channels except Online Travel Agencies (OTA); gds_only = Global Distribution System (GDS) only; brand_website_only = brand.com only.. Valid values are `all_channels|direct_only|ota_excluded|gds_only|brand_website_only`',
    `closed_to_arrival` BOOLEAN COMMENT 'Indicates whether the overridden rate includes a Closed to Arrival (CTA) restriction, preventing new reservations with an arrival date falling within the override effective window. True = CTA restriction active; False = arrivals permitted.',
    `closed_to_departure` BOOLEAN COMMENT 'Indicates whether the overridden rate includes a Closed to Departure (CTD) restriction, preventing check-outs on specific dates within the override window. True = CTD restriction active; False = departures permitted.',
    `competitive_rate_reference` DECIMAL(18,2) COMMENT 'The competitor or market reference rate (in property local currency) that informed the override decision, particularly when override_reason_code is competitive_pressure. Sourced from STR STAR Report, OTA rate shopping, or RMS competitive benchmarking module.',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the pricing override record was first created in the data platform. Used for data lineage, audit trail, and Silver layer ingestion tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the rates captured in this override record (e.g., USD, EUR, GBP). Ensures multi-currency properties report rates in the correct denomination.. Valid values are `^[A-Z]{3}$`',
    `day_of_week_mask` STRING COMMENT 'Seven-character binary string (1=active, 0=inactive) representing the days of the week the override applies to, ordered Monday through Sunday (e.g., 1111100 = Monâ€“Fri only). Applicable when override_scope is day_of_week.. Valid values are `^[01]{7}$`',
    `effective_date` DATE COMMENT 'The first calendar date on which the pricing override rate becomes active and is applied to reservations. Defines the start of the override window in the propertys local time zone.',
    `expiry_date` DATE COMMENT 'The last calendar date on which the pricing override rate remains active. After this date, the override status transitions to expired and the RMS-recommended rate is reinstated. Nullable for open-ended overrides.',
    `inventory_rooms_affected` STRING COMMENT 'Number of room inventory units to which the pricing override applies. Null or zero indicates the override applies to all available inventory for the specified room type and date range.',
    `is_bar_override` BOOLEAN COMMENT 'Indicates whether this override specifically targets the Best Available Rate (BAR) â€” the lowest publicly available rate for a given date. True = BAR is being overridden; False = override applies to a non-BAR rate plan.',
    `los_restriction_max` STRING COMMENT 'Maximum number of nights a guest may stay under the overridden rate. Null if no maximum LOS restriction is applied. Used in conjunction with los_restriction_min to define the eligible stay window.',
    `los_restriction_min` STRING COMMENT 'Minimum number of nights a guest must stay to qualify for the overridden rate. A Length of Stay (LOS) restriction applied alongside the rate override to manage demand patterns and prevent single-night bookings during high-demand periods.',
    `override_notes` STRING COMMENT 'Free-text narrative provided by the revenue manager explaining the business rationale for the override, particularly when override_reason_code is other or when additional context is required for audit purposes.',
    `override_rate` DECIMAL(18,2) COMMENT 'The manually set rate (in property local currency) applied by the revenue manager, superseding the RMS-recommended rate. This is the Best Available Rate (BAR) or specific rate plan rate that will be published to distribution channels.',
    `override_reason_code` STRING COMMENT 'Standardized reason code classifying why the revenue manager overrode the system-generated rate. competitive_pressure = OTA/competitor rate response; group_wash = group block displacement adjustment; event_demand = MICE or local event surge; error_correction = RMS data or configuration error fix; distressed_inventory = last-minute unsold inventory; other = non-standard reason documented in override_notes. [ENUM-REF-CANDIDATE: competitive_pressure|group_wash|event_demand|error_correction|distressed_inventory|other â€” promote to reference product]. Valid values are `competitive_pressure|group_wash|event_demand|error_correction|distressed_inventory|other`',
    `override_reference_number` STRING COMMENT 'Externally visible alphanumeric reference number assigned to the pricing override for audit trail, cross-system reconciliation, and revenue manager communication. Format: PO- followed by 6â€“20 alphanumeric characters.. Valid values are `^PO-[A-Z0-9]{6,20}$`',
    `override_scope` STRING COMMENT 'Defines the temporal scope of the pricing override. single_date = applies to one specific stay date; date_range = applies across a contiguous range from effective_date to expiry_date; day_of_week = applies to specific days of the week within the effective window.. Valid values are `single_date|date_range|day_of_week`',
    `override_status` STRING COMMENT 'Current lifecycle state of the pricing override. pending = submitted awaiting approval; approved = authorized and scheduled; active = currently in effect; expired = past effective end date; reversed = manually cancelled or rolled back.. Valid values are `pending|approved|active|expired|reversed`',
    `rate_variance_amount` DECIMAL(18,2) COMMENT 'Absolute monetary difference between the override_rate and the rms_recommended_rate (override_rate minus rms_recommended_rate). Positive value indicates override is above RMS recommendation; negative indicates below. Used for override impact analysis.',
    `rate_variance_pct` DECIMAL(18,2) COMMENT 'Percentage deviation of the override_rate from the rms_recommended_rate, expressed as a decimal (e.g., 0.1500 = 15%). Calculated as (override_rate - rms_recommended_rate) / rms_recommended_rate. Supports threshold-based alerting and RMS calibration.',
    `reversal_reason` STRING COMMENT 'Free-text or coded explanation for why the pricing override was reversed. Populated only when override_status is reversed. Supports post-mortem analysis of override quality and revenue impact of reversals.',
    `reversed_timestamp` TIMESTAMP COMMENT 'The date and time when the pricing override was reversed or cancelled, restoring the RMS-recommended rate. Null for overrides that have not been reversed.',
    `rms_forecast_demand_level` STRING COMMENT 'The demand level classification (low, medium, high, very_high) as forecasted by the RMS at the time the override was submitted. Provides context for evaluating whether the override was aligned with or contrary to demand signals.. Valid values are `low|medium|high|very_high`',
    `rms_recommended_rate` DECIMAL(18,2) COMMENT 'The original rate (in property local currency) recommended by the automated Revenue Management System (IDeaS G3 RMS or Infor EzRMS) prior to the manual override. Baseline for override variance analysis and RMS tuning.',
    `rms_source_system` STRING COMMENT 'Identifies the Revenue Management System (RMS) that generated the original recommended rate being overridden. ideas_g3 = IDeaS G3 RMS; infor_ezrms = Infor EzRMS; manual = no RMS recommendation existed (fully manual rate entry).. Valid values are `ideas_g3|infor_ezrms|manual`',
    `submitted_timestamp` TIMESTAMP COMMENT 'The date and time (ISO 8601 with timezone offset) when the revenue manager submitted the pricing override request for approval. Represents the principal business event time for this transaction.',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording the most recent modification to the pricing override record in the data platform. Supports change detection and incremental processing in the Databricks Lakehouse Silver layer.',
    CONSTRAINT pk_pricing_override PRIMARY KEY(`pricing_override_id`)
) COMMENT 'Transactional record of manual pricing overrides applied by revenue managers to supersede system-generated rates from IDeaS G3 RMS. Captures original system-recommended rate, override rate, override reason code (competitive pressure, group wash, event demand, error correction), approving revenue manager, property, room type, rate plan, effective date range, and override status (pending, approved, expired, reversed). Provides audit trail for manual revenue management interventions and supports override frequency analysis for RMS tuning.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`rate_availability` (
    `rate_availability_id` BIGINT COMMENT 'Unique surrogate identifier for each daily rate and availability snapshot record in the Silver layer lakehouse. Primary key for the rate_availability data product.',
    `cancellation_policy_id` BIGINT COMMENT 'Foreign key linking to reservation.cancellation_policy. Business justification: Rate availability snapshots distributed to OTAs and GDS must include the specific cancellation policy for rate shopping compliance and guest transparency. Channel managers need this link to ensure acc',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: Daily rate availability snapshots are directly driven by demand forecast levels. rate_availability.demand_forecast_level (STRING) is a denormalized categorical reference; adding demand_forecast_id as ',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Rate/availability snapshots are channel-specific - each channel sees different rates and inventory based on connectivity and contracts. Core distribution management requires tracking what each channel',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Reference to the Dynamic Rate Rule (DRR) applied by IDeaS G3 RMS to derive the current BAR for this snapshot. DRRs define the algorithmic pricing logic (demand-based adjustments, day-of-week factors, lead-time curves) that drive dynamic pricing decisions.',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel, resort, or vacation property) for which this rate and availability snapshot applies. Sourced from Oracle OPERA PMS property configuration.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan (e.g., BAR, LRA, NRR, corporate, package) governing the pricing for this snapshot. Sourced from IDeaS G3 RMS and Sabre SynXis CRS rate plan catalog.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which this rate and availability snapshot is captured. Sourced from Oracle OPERA PMS room type configuration.',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Daily rate availability snapshots are generated within the context of the active revenue strategy. Adding strategy_id links each rate availability record to the governing strategy, enabling analysis o',
    `advance_purchase_days` STRING COMMENT 'Minimum number of days in advance a booking must be made to qualify for this rate plan on the snapshot date (e.g., 7-day advance purchase, 21-day advance purchase for NRR rates). A key rate restriction parameter managed in IDeaS G3 RMS and Sabre SynXis CRS.',
    `availability_status` STRING COMMENT 'Current open/closed availability status for this property, room type, rate plan, and date combination as managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. open = bookable; closed = inventory blocked; stop_sell = yield-driven closure; on_request = requires manual confirmation; min_stay_restriction = LOS restriction active; closed_to_arrival = no new arrivals permitted on this date.. Valid values are `open|closed|on_request|stop_sell|min_stay_restriction|closed_to_arrival`',
    `available_rooms` STRING COMMENT 'Number of rooms of this room type available for sale on the snapshot date at this property. Represents net sellable inventory after deducting out-of-order, out-of-service, and already-committed rooms. Core input for OCC (Occupancy Rate) and RevPAR calculations.',
    `bar_rate` DECIMAL(18,2) COMMENT 'The Best Available Rate (BAR) for this room type, property, and stay date â€” the lowest publicly available non-restricted rate as determined by IDeaS G3 RMS dynamic pricing engine. BAR is the anchor rate from which other rate plans are derived and is the primary rate distributed via Sabre SynXis CRS and OTA channels.',
    `closed_to_arrival` BOOLEAN COMMENT 'Indicates whether new arrivals are blocked on the snapshot date for this room type and rate plan. When True, guests cannot check in on this date but may continue an existing stay through it. A yield management restriction used to optimize multi-night booking patterns.',
    `closed_to_departure` BOOLEAN COMMENT 'Indicates whether departures are blocked on the snapshot date for this room type and rate plan. When True, guests cannot check out on this date, forcing stays to extend through it. Used in conjunction with CTA restrictions to shape booking patterns during peak periods.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this rate and availability snapshot record was first created in the Silver layer lakehouse. Serves as the audit creation timestamp for data lineage and ETL pipeline tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which all rate amounts (BAR, min, max, rack) for this record are denominated (e.g., USD, EUR, GBP). Required for multi-currency properties and international channel distribution via Sabre SynXis CRS.. Valid values are `^[A-Z]{3}$`',
    `demand_forecast_level` STRING COMMENT 'Demand forecast classification for the snapshot date as generated by IDeaS G3 RMS or Infor EzRMS. Drives dynamic pricing decisions and inventory restriction strategies. Levels range from very_low (deep discounting warranted) to very_high (maximum rate and stop-sell controls active).. Valid values are `very_low|low|medium|high|very_high`',
    `effective_from_timestamp` TIMESTAMP COMMENT 'The date and time from which this rate and availability record became active and was distributed to booking channels. Used for bi-temporal modeling of rate history and supports point-in-time rate reconstruction for revenue audits and dispute resolution.',
    `effective_until_timestamp` TIMESTAMP COMMENT 'The date and time until which this rate and availability record remains active. Null indicates the record is currently active. Used for bi-temporal modeling and historical rate reconstruction. When a new rate update is received, the prior records effective_until_timestamp is set to the new records effective_from_timestamp.',
    `gds_rate_code` STRING COMMENT 'The rate code as published on GDS (Global Distribution System) platforms (Sabre, Amadeus, Travelport) via Sabre SynXis CRS. GDS rate codes follow standardized formats required for travel agent booking systems and corporate travel management programs.. Valid values are `^[A-Z0-9]{2,8}$`',
    `group_block_rooms` STRING COMMENT 'Number of rooms on the snapshot date allocated to group blocks (MICE, corporate groups, tour operators) as managed in Oracle OPERA PMS and Delphi by Amadeus. Group block inventory is excluded from transient availability and tracked separately for yield optimization.',
    `is_package_rate` BOOLEAN COMMENT 'Indicates whether this rate plan includes bundled package components (e.g., breakfast, spa credit, parking, airport transfer) beyond the base room charge. Package rates require component-level revenue allocation across USALI departments in Oracle OPERA PMS.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'The date and time when this rate and availability record was last modified in the source system (IDeaS G3 RMS or Sabre SynXis CRS). Represents the business event timestamp of the most recent pricing or availability change. Critical for real-time channel distribution synchronization and SLA monitoring.',
    `los_maximum` STRING COMMENT 'Maximum number of nights permitted under this rate plan for the snapshot date. Used to prevent long-stay bookings at promotional rates during high-demand periods. Managed in IDeaS G3 RMS as an upper LOS (Length of Stay) restriction.',
    `los_minimum` STRING COMMENT 'Minimum number of nights a guest must stay to qualify for this rate plan on the snapshot date. A key yield optimization restriction managed in IDeaS G3 RMS. LOS (Length of Stay) restrictions are used to maximize revenue during high-demand periods by requiring multi-night commitments.',
    `max_rate` DECIMAL(18,2) COMMENT 'The ceiling rate (maximum sellable rate) for this room type, property, rate plan, and stay date as configured in IDeaS G3 RMS. Caps pricing during peak demand periods to maintain guest trust and brand integrity, and supports rate parity compliance across channels.',
    `meal_plan_code` STRING COMMENT 'Code indicating the meal plan inclusion for this rate plan (RO = Room Only; BB = Bed and Breakfast; HB = Half Board; FB = Full Board; AI = All Inclusive). Affects rate composition, F&B revenue allocation, and package pricing in Oracle OPERA PMS and MICROS POS.. Valid values are `RO|BB|HB|FB|AI`',
    `min_rate` DECIMAL(18,2) COMMENT 'The floor rate (minimum sellable rate) for this room type, property, rate plan, and stay date as configured in IDeaS G3 RMS. Represents the lowest price at which the room may be sold under any circumstance, enforcing revenue floor controls and preventing rate erosion.',
    `occupancy_forecast_pct` DECIMAL(18,2) COMMENT 'Forecasted occupancy rate (OCC%) for the property on the snapshot date as projected by IDeaS G3 RMS or Infor EzRMS at the time of this snapshot. Expressed as a percentage (0.00â€“100.00). Used to validate pricing decisions and benchmark against STR STAR Report actuals.',
    `ota_rate_code` STRING COMMENT 'The rate identifier as assigned by the primary OTA (Online Travel Agency) partner (e.g., Expedia, Booking.com) for this rate plan and property combination. Used for rate parity monitoring, OTA reconciliation, and channel performance reporting.',
    `out_of_order_rooms` STRING COMMENT 'Number of rooms of this room type that are out of order (OOO) on the snapshot date due to maintenance, renovation, or damage. Out-of-order rooms are excluded from sellable inventory and impact OCC denominator calculations per USALI standards.',
    `pickup_rooms` STRING COMMENT 'Number of rooms booked (picked up) for the snapshot date since the previous snapshot capture. Pickup velocity is a key revenue management signal used in IDeaS G3 RMS and Infor EzRMS to detect demand acceleration and trigger dynamic rate adjustments.',
    `pricing_override_flag` BOOLEAN COMMENT 'Indicates whether the current rate for this snapshot was manually overridden by a revenue manager, superseding the automated recommendation from IDeaS G3 RMS or Infor EzRMS. Manual overrides are tracked for revenue strategy audit and RMS model calibration.',
    `pricing_override_reason` STRING COMMENT 'Free-text or coded reason provided by the revenue manager when manually overriding the RMS-recommended rate. Populated only when pricing_override_flag is True. Used for revenue strategy review, RMS model improvement, and audit trail compliance.',
    `rack_rate` DECIMAL(18,2) COMMENT 'The published full undiscounted rate (rack rate) for this room type and stay date. Serves as the reference rate for discount calculations, loyalty redemption valuations, and walk-in pricing. Typically the highest rate tier and the baseline for USALI revenue reporting.',
    `rate_parity_flag` BOOLEAN COMMENT 'Indicates whether this rate record is subject to rate parity obligations with OTA (Online Travel Agency) partners. When True, the rate must match or be lower than rates published on OTA channels. Critical for OTA contract compliance and channel distribution management.',
    `rate_plan_code` STRING COMMENT 'Alphanumeric code identifying the rate plan as distributed via Sabre SynXis CRS and IDeaS G3 RMS (e.g., BAR, CORP01, PKG_BB, NRR_ADV21). Used for channel distribution, GDS mapping, and OTA rate loading.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_plan_type` STRING COMMENT 'Classification of the rate plan governing this availability record. Determines pricing logic, cancellation policy, and channel eligibility. BAR (Best Available Rate) = dynamic public rate; LRA (Last Room Availability) = guaranteed availability; NRR (Non-Refundable Rate) = prepaid non-cancellable; corporate = negotiated account rate; package = bundled inclusions; group = block rate; loyalty = member rate; promotional = limited-time offer; wholesale = OTA/tour operator net rate. [ENUM-REF-CANDIDATE: bar|lra|nrr|corporate|package|group|loyalty|promotional|wholesale â€” promote to reference product]',
    `revenue_management_system` STRING COMMENT 'Identifies the Revenue Management System (RMS) that generated or last updated the pricing recommendation for this snapshot record. Supports data lineage tracking and system-of-record attribution for audit and reconciliation purposes.. Valid values are `ideasg3|infor_ezrms|manual|opera_pms`',
    `snapshot_date` DATE COMMENT 'The stay date (arrival night) for which this rate and availability record applies. Represents the business event date â€” the night a guest would occupy the room at the stated rate. Core dimension for RevPAR and ADR reporting.',
    `source_system_record_reference` STRING COMMENT 'The native record identifier from the originating source system (IDeaS G3 RMS or Sabre SynXis CRS) for this rate and availability record. Enables traceability back to the system of record for reconciliation, reprocessing, and audit purposes.',
    `stop_sell` BOOLEAN COMMENT 'Indicates whether this room type and rate plan combination has been closed to all new bookings on the snapshot date regardless of available inventory. A hard yield management control applied in IDeaS G3 RMS to protect inventory for higher-value bookings or group blocks.',
    `total_rooms` STRING COMMENT 'Total physical room count for this room type at the property on the snapshot date. Used as the denominator for occupancy rate (OCC) and RevPAR calculations. Reflects the propertys sellable capacity before any restrictions.',
    CONSTRAINT pk_rate_availability PRIMARY KEY(`rate_availability_id`)
) COMMENT 'Daily rate and availability snapshot per property, room type, and rate plan combination as managed in IDeaS G3 RMS and distributed via Sabre SynXis CRS. Captures open/closed status, available inventory count, current BAR, minimum and maximum rates, and last-updated timestamp. Represents the real-time pricing grid used for reservation fulfillment and channel distribution.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`demand_forecast` (
    `demand_forecast_id` BIGINT COMMENT 'Unique surrogate identifier for each demand forecast record generated by IDeaS G3 RMS or Infor EzRMS. Primary key for the demand_forecast data product in the Databricks Silver Layer.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Demand forecast models must incorporate active loyalty promotions (double-points, tier challenges) to adjust projected pickup. Named process: promotion-adjusted demand forecasting. RMS systems explici',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Demand forecasts incorporate expected lift from planned marketing campaigns. Forecasters link campaigns to forecast assumptions for post-campaign variance analysis and to refine future campaign lift m',
    `competitive_set_id` BIGINT COMMENT 'Foreign key linking to revenue.competitive_set. Business justification: demand_forecast contains rgi_forecast, mpi_forecast, and ari_forecast competitive index projections. These metrics are computed relative to a specific competitive set (STR STAR Report). Adding competi',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Demand forecasts incorporate known definite event bookings as constrained demand drivers. Critical for pickup forecasting, unconstrained vs constrained demand modeling, and event impact analysis in re',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Demand forecasts are produced on fiscal period cadence to support budget variance analysis and financial planning. Revenue and finance teams reconcile forecasted vs. budgeted room revenue by fiscal pe',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Room demand forecasts drive outlet-level staffing and inventory planning (high occupancy forecast = increase outlet labor/stock). Required for integrated labor scheduling, procurement planning, outlet',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: Total revenue management requires F&B demand forecasting at the revenue center level (e.g., forecasting covers and revenue for the main restaurant vs. bar) to drive labor scheduling and purchasing. Th',
    `gss_score_id` BIGINT COMMENT 'Foreign key linking to experience.gss_score. Business justification: Demand forecasting models incorporate property GSS scores as a demand driver (higher satisfaction correlates with higher unconstrained demand). Revenue management systems use satisfaction metrics as r',
    `market_segment_id` BIGINT COMMENT 'Reference to the market segment (e.g., Transient, Group, Corporate, Leisure, OTA) for which the demand forecast is generated. Null when the forecast is at the property or room-type level only.',
    `property_id` BIGINT COMMENT 'Reference to the hotel or resort property for which this demand forecast was generated. Aligns with the Oracle OPERA PMS property master.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which the demand forecast is generated. Null when the forecast is at the property or market-segment level only.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: RMS demand forecasts are calibrated against seasonal demand classifications, holiday flags, and estimated occupancy from seasonal_calendar. Direct FK replaces denormalized season_code on demand_foreca',
    `ari_forecast` DECIMAL(18,2) COMMENT 'Forecasted Average Rate Index (ARI), representing the propertys projected ADR relative to the competitive sets projected ADR. An ARI above 1.0 indicates the property is expected to achieve a rate premium over its competitive set.',
    `booking_pace_index` DECIMAL(18,2) COMMENT 'Ratio of current bookings on-hand for the forecast date compared to the same point in time in the prior year or baseline period. A value above 1.0 indicates ahead-of-pace demand; below 1.0 indicates behind-pace. Used by revenue managers to assess demand trajectory.',
    `confidence_interval_lower` DECIMAL(18,2) COMMENT 'Lower bound of the statistical confidence interval for the unconstrained demand forecast. Represents the pessimistic demand scenario used for risk-adjusted pricing and inventory control decisions in IDeaS G3 RMS.',
    `confidence_interval_upper` DECIMAL(18,2) COMMENT 'Upper bound of the statistical confidence interval for the unconstrained demand forecast. Represents the optimistic demand scenario used for overbooking strategy and group evaluation in IDeaS G3 RMS.',
    `confidence_level_pct` DECIMAL(18,2) COMMENT 'Statistical confidence level (e.g., 90.00, 95.00) associated with the forecast confidence interval. Indicates the probability that actual demand will fall within the lower and upper confidence bounds.',
    `constrained_demand` DECIMAL(18,2) COMMENT 'The forecasted room demand (in room-nights) after applying available inventory capacity constraints. Represents the demand the property can actually accommodate. Used for occupancy projection and revenue optimization.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this demand forecast record was first captured and written to the Silver Layer data product. Used for audit trail and data lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary forecast values in this record (e.g., USD, EUR, GBP). Ensures multi-currency properties report revenue in the correct denomination.. Valid values are `^[A-Z]{3}$`',
    `day_of_week` STRING COMMENT 'Day of the week corresponding to the forecast date. Used for day-of-week demand pattern analysis, weekend vs. weekday segmentation, and pricing strategy differentiation. [ENUM-REF-CANDIDATE: Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday â€” 7 candidates stripped; promote to reference product]',
    `demand_segment_mix_pct` DECIMAL(18,2) COMMENT 'Forecasted percentage share of total demand attributed to the specific market segment in this record. For example, if the Transient segment is expected to represent 65% of total demand on the forecast date, this field holds 65.00. Populated only for market-segment-level forecasts.',
    `forecast_accuracy_mape` DECIMAL(18,2) COMMENT 'Mean Absolute Percentage Error (MAPE) of the forecast model for this property-segment-horizon combination, based on historical back-testing. Lower values indicate higher model accuracy. Used to weight forecast confidence and flag low-accuracy forecasts for revenue manager review.',
    `forecast_date` DATE COMMENT 'The stay date (arrival date) for which the demand forecast values apply. Represents the future date being predicted, formatted as yyyy-MM-dd.',
    `forecast_granularity` STRING COMMENT 'The dimensional level at which this forecast record is generated. property is the highest level; room_type_segment is the most granular, combining room type and market segment dimensions as supported by IDeaS G3 RMS.. Valid values are `property|room_type|market_segment|room_type_segment`',
    `forecast_horizon_days` STRING COMMENT 'Number of days from the forecast run date to the forecast date, representing how far into the future this forecast projects. For example, a forecast run on 2024-01-01 for a stay date of 2024-04-01 has a horizon of 90 days. Used to assess forecast accuracy by horizon bucket.',
    `forecast_model_type` STRING COMMENT 'Classification of the algorithmic approach used to generate the forecast. time_series uses historical booking patterns; regression uses demand drivers; machine_learning uses ML-based models; hybrid combines multiple approaches; manual_override indicates a revenue manager manually adjusted the system forecast.. Valid values are `time_series|regression|machine_learning|hybrid|manual_override`',
    `forecast_model_version` STRING COMMENT 'Version identifier of the demand forecasting model or algorithm used to generate this forecast record (e.g., IDeaS-G3-v8.2, EzRMS-v5.1). Enables model performance tracking, A/B comparison, and audit of forecast methodology changes.',
    `forecast_run_reference` STRING COMMENT 'Externally-known unique identifier assigned by the Revenue Management System (RMS) to the specific forecast generation run that produced this record. Enables traceability back to the originating RMS batch or on-demand run.',
    `forecast_run_timestamp` TIMESTAMP COMMENT 'The date and time when this forecast record was generated by the Revenue Management System. Represents the principal business event timestamp for this transaction, formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `forecast_status` STRING COMMENT 'Current lifecycle state of this forecast record. active indicates the current operative forecast; superseded indicates a newer run has replaced it; draft indicates a preliminary run not yet published to pricing decisions; published indicates the forecast has been released to the Revenue Management System for pricing action; archived indicates historical retention only.. Valid values are `active|superseded|draft|published|archived`',
    `forecast_type` STRING COMMENT 'Classification of the forecast methodology or purpose. unconstrained reflects true market demand without inventory limits; constrained reflects demand limited by available inventory; group_evaluation is used for group block assessment in IDeaS G3 RMS; pickup reflects incremental booking pace; budget reflects the annual budget forecast baseline.. Valid values are `unconstrained|constrained|group_evaluation|pickup|budget`',
    `is_holiday` BOOLEAN COMMENT 'Flag indicating whether the forecast date falls on a public or national holiday in the propertys market. Used to apply holiday demand adjustment factors in the forecasting model.',
    `is_override` BOOLEAN COMMENT 'Flag indicating whether a revenue manager manually overrode the system-generated forecast values for this record. When true, the forecast reflects human judgment rather than pure algorithmic output. Used to track override frequency and assess model trust.',
    `is_special_event` BOOLEAN COMMENT 'Flag indicating whether the forecast date coincides with a special event (e.g., conference, concert, sporting event, public holiday) that is expected to materially impact demand. When true, the forecast may incorporate event-specific demand uplift factors.',
    `mpi_forecast` DECIMAL(18,2) COMMENT 'Forecasted Market Penetration Index (MPI), representing the propertys projected occupancy share relative to the competitive sets projected occupancy. An MPI above 1.0 indicates the property is expected to capture more than its fair share of market demand.',
    `projected_adr` DECIMAL(18,2) COMMENT 'Forecasted Average Daily Rate (ADR) in the propertys local currency for the forecast date. Represents the expected average revenue per occupied room. Core revenue management KPI used to drive pricing strategy.',
    `projected_cancellations` DECIMAL(18,2) COMMENT 'Forecasted number of room-nights expected to cancel from the current on-books position before the forecast date. Used to calculate net demand and inform overbooking strategy.',
    `projected_no_shows` DECIMAL(18,2) COMMENT 'Forecasted number of room-nights expected to result in no-show arrivals on the forecast date. Used alongside cancellation forecasts to calibrate overbooking levels and protect revenue.',
    `projected_occupancy_pct` DECIMAL(18,2) COMMENT 'Forecasted occupancy rate expressed as a percentage of available rooms expected to be sold on the forecast date. Calculated as constrained demand divided by total available rooms. Key input to RevPAR and yield optimization decisions.',
    `projected_pickup` DECIMAL(18,2) COMMENT 'Forecasted incremental room-nights expected to be booked between the forecast run date and the forecast date. Represents the additional demand the RMS expects to materialize beyond rooms already on books.',
    `projected_revpar` DECIMAL(18,2) COMMENT 'Forecasted Revenue Per Available Room (RevPAR) in the propertys local currency for the forecast date. Derived as projected ADR multiplied by projected occupancy rate. Primary yield optimization metric used by Revenue Management.',
    `projected_room_revenue` DECIMAL(18,2) COMMENT 'Forecasted total room revenue in the propertys local currency for the forecast date. Calculated as projected rooms sold multiplied by projected ADR. Used for budget variance analysis and revenue strategy.',
    `projected_rooms_available` STRING COMMENT 'Forecasted number of rooms available for sale on the forecast date after accounting for out-of-order, out-of-service, and maintenance blocks. Denominator for occupancy and RevPAR calculations.',
    `projected_rooms_sold` STRING COMMENT 'Forecasted number of rooms expected to be sold (occupied) on the forecast date. Used for housekeeping scheduling, staffing planning, and inventory control decisions.',
    `rgi_forecast` DECIMAL(18,2) COMMENT 'Forecasted Revenue Generation Index (RGI), representing the propertys projected RevPAR relative to the competitive sets projected RevPAR. An RGI above 1.0 indicates the property is expected to outperform its competitive set. Sourced from STR STAR Report benchmarking data integrated into Infor EzRMS.',
    `rooms_on_books` STRING COMMENT 'Number of rooms already confirmed (on books) for the forecast date at the time the forecast was generated. Represents the definite demand component; the RMS adds pickup forecast to arrive at total projected demand.',
    `source_system` STRING COMMENT 'Identifies the operational system of record that generated this demand forecast record. IDeaS_G3_RMS indicates the IDeaS G3 Revenue Management System; Infor_EzRMS indicates the Infor EzRMS system; Manual indicates a revenue manager-entered forecast override.. Valid values are `IDeaS_G3_RMS|Infor_EzRMS|Manual`',
    `special_event_name` STRING COMMENT 'Name or description of the special event influencing demand on the forecast date (e.g., Super Bowl LIX, New Year Eve, City Marathon). Populated only when is_special_event is true.',
    `unconstrained_demand` DECIMAL(18,2) COMMENT 'The total forecasted room demand (in room-nights) without any inventory capacity constraints applied. Represents true market demand as estimated by the RMS model. Used to identify demand compression and inform inventory control decisions.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this demand forecast record was last modified in the Silver Layer, such as when a revised forecast supersedes a prior run for the same forecast date and segment.',
    CONSTRAINT pk_demand_forecast PRIMARY KEY(`demand_forecast_id`)
) COMMENT 'Forward-looking demand forecast records generated by IDeaS G3 RMS and Infor EzRMS at the property, room type, and market segment level. Captures forecast date, forecast horizon, unconstrained demand, constrained demand, projected occupancy, projected ADR, projected RevPAR, forecast confidence interval, and forecast model version. Used to drive pricing decisions, inventory controls, and group evaluation.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`inventory_control` (
    `inventory_control_id` BIGINT COMMENT 'Primary key for inventory_control',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: inventory_control.demand_forecast_rooms (DECIMAL) is a denormalized copy of the projected rooms figure from the demand forecast. Adding demand_forecast_id normalizes this relationship so the full fore',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Inventory controls (sell limits, hurdles, stop-sells) vary by channel. Revenue managers allocate inventory differently across direct, OTA, GDS channels based on profitability and strategy. Fundamental',
    `dynamic_rate_rule_id` BIGINT COMMENT 'Reference to the Dynamic Rate Rule (DRR) applied to derive the current_bar for this room type and stay date. Links to the pricing strategy configuration governing automated rate adjustments in IDeaS G3 RMS.',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Inventory controls (sell limits, hurdle rates, overbooking caps) are adjusted based on event booking displacement analysis. Essential for inventory optimization around events and group block allocatio',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel, resort, or vacation property) to which this inventory control record applies. Aligns with Oracle OPERA PMS property configuration and IDeaS G3 RMS property setup.',
    `reservation_group_block_id` BIGINT COMMENT 'Foreign key linking to reservation.reservation_group_block. Business justification: Inventory control records manage group_block_rooms allotments. Linking inventory_control to reservation_group_block enables allotment-vs-contracted room count reconciliation â€” a standard revenue/inven',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Inventory controls reserve allotments for specific loyalty tiers (e.g., guaranteed availability for Platinum members per program benefits). Named process: tier-based inventory allotment and guaranteed',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the rate plan (e.g., BAR, LRA, NRR, corporate, package) associated with this inventory control record. Determines the pricing tier and restrictions applied to the available inventory.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type (e.g., King Deluxe, Double Standard, Suite) for which this inventory control record is defined. Aligns with Oracle OPERA PMS room type configuration and IDeaS G3 RMS room class setup.',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: inventory_control.inventory_control_approach (STRING) references the strategic approach governing inventory decisions. Adding strategy_id links each inventory control record to the revenue strategy th',
    `allotment_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date allocated to contracted allotments (OTA allotments, wholesale, tour operator contracts). Managed via Sabre SynXis CRS channel management and reduces the freely-sellable transient inventory.',
    `approval_authority` STRING COMMENT 'Designates the level of authority required to approve the overbooking level for this inventory control record. Ensures governance and accountability for overbooking decisions per property SOPs and SOX internal control requirements.. Valid values are `rms_automated|revenue_manager|director_of_revenue|general_manager`',
    `available_room_count` STRING COMMENT 'Real-time count of rooms available for sale for this property, room type, stay date, and rate plan combination at the time of last update. Reflects physical inventory minus confirmed reservations, group blocks, and out-of-order rooms. Distributed via Sabre SynXis CRS for reservation fulfillment.',
    `control_record_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this inventory control record as referenced in IDeaS G3 RMS and Sabre SynXis CRS. Used for cross-system reconciliation and audit traceability.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `control_status` STRING COMMENT 'Current lifecycle state of this inventory control record indicating whether the room type/rate plan combination is open for sale, closed, restricted, pending review, or subject to a manual override. This is the real-time availability state distributed via Sabre SynXis CRS.. Valid values are `open|closed|restricted|pending|override`',
    `control_type` STRING COMMENT 'Classifies the category of inventory control applied to this record. Determines how the control_value is interpreted and enforced by the Revenue Management System. [ENUM-REF-CANDIDATE: hurdle_rate|sell_limit|overbooking_level|los_restriction|cta_restriction|ctd_restriction|allotment|group_block â€” promote to reference product]. Valid values are `hurdle_rate|sell_limit|overbooking_level|los_restriction|cta_restriction|ctd_restriction`',
    `control_value` DECIMAL(18,2) COMMENT 'The operative value for this control record as applied by the Revenue Management System. Interpretation depends on control_type: for hurdle_rate it is the minimum acceptable rate in local currency; for sell_limit it is the maximum rooms to sell; for overbooking_level it is the number of rooms above physical capacity authorized to sell.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control record was first created in the source Revenue Management System (IDeaS G3 RMS or Infor EzRMS). Provides the audit trail creation anchor for data lineage and SOX compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary rate fields in this record (current_bar, min_rate, max_rate, hurdle_rate). Ensures multi-currency properties report rates in the correct denomination.. Valid values are `^[A-Z]{3}$`',
    `current_bar` DECIMAL(18,2) COMMENT 'The current Best Available Rate (BAR) in local currency for this room type and stay date as published via Sabre SynXis CRS and channel distribution. Represents the lowest publicly available non-restricted rate and is the primary pricing signal for transient demand.',
    `effective_from_timestamp` TIMESTAMP COMMENT 'The date and time from which this inventory control records control_value and restrictions became operative in the Revenue Management System. Supports temporal validity tracking and historical rate/availability grid reconstruction.',
    `effective_until_timestamp` TIMESTAMP COMMENT 'The date and time at which this inventory control records control_value and restrictions ceased to be operative. Null for currently active records. Enables point-in-time historical analysis of the rate/availability grid.',
    `group_block_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date allocated to group blocks (MICE, tour groups, corporate groups). Reduces the transient sell limit and is managed via Delphi by Amadeus group block management and IDeaS G3 RMS group evaluation.',
    `hurdle_rate` DECIMAL(18,2) COMMENT 'Minimum acceptable rate (in local currency) below which a reservation for this room type on the stay date should not be accepted, as determined by the Revenue Management System. Used in displacement analysis and group evaluation in IDeaS G3 RMS.',
    `is_closed_to_arrival` BOOLEAN COMMENT 'Indicates whether arrivals are blocked for this room type and rate plan on the stay date (Closed to Arrival / CTA restriction). When True, guests may not check in on this date but may stay through it as part of a longer booking.',
    `is_closed_to_departure` BOOLEAN COMMENT 'Indicates whether departures are blocked for this room type and rate plan on the stay date (Closed to Departure / CTD restriction). When True, guests may not check out on this date, requiring stays to extend beyond it.',
    `is_override` BOOLEAN COMMENT 'Indicates whether the applied control_value represents a manual override of the system_recommended_value. True when a revenue manager has manually intervened; False when the system recommendation was accepted as-is. Critical for RMS model performance auditing.',
    `last_distributed_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control records rate and availability state was last successfully distributed to Sabre SynXis CRS and downstream channels (OTA, GDS). Critical for SLA monitoring and channel distribution reconciliation.',
    `max_los` STRING COMMENT 'Maximum number of nights a guest may stay when booking this room type at this rate plan on the stay date. Used to prevent long-stay displacement of higher-value transient demand during peak periods.',
    `max_rate` DECIMAL(18,2) COMMENT 'The ceiling rate in local currency above which no rate plan for this room type and stay date may be sold. Used to enforce rate integrity, prevent rate gouging, and comply with local pricing regulations during high-demand periods.',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must stay to be eligible to book this room type at this rate plan on the stay date. A Length of Stay (LOS) restriction used to optimize revenue during high-demand periods by requiring longer stays.',
    `min_rate` DECIMAL(18,2) COMMENT 'The absolute floor rate in local currency below which no rate plan for this room type and stay date may be sold, regardless of channel or negotiated agreement. Enforced as a hard constraint in the Revenue Management System and CRS.',
    `occupancy_on_books` DECIMAL(18,2) COMMENT 'Current confirmed occupancy rate (OCC) percentage for this room type on the stay date at the time of last update, calculated as confirmed reservations divided by physical_room_count. Key input to dynamic pricing and sell limit decisions in the Revenue Management System.',
    `out_of_order_rooms` STRING COMMENT 'Number of rooms of this room type on the stay date designated as out of order (OOO) due to maintenance, renovation, or FF&E replacement. These rooms are excluded from sellable inventory and occupancy calculations per USALI standards.',
    `overbooking_absolute_cap` STRING COMMENT 'Hard ceiling on the absolute number of rooms that may be overbooked above physical capacity for this room type on the stay date, regardless of the overbooking_pct calculation. Prevents excessive walk exposure during high-demand periods.',
    `overbooking_pct` DECIMAL(18,2) COMMENT 'Maximum authorized overbooking level expressed as a percentage above physical room capacity for this room type on the stay date. Defined in the overbooking policy and used by IDeaS G3 RMS to set the sell limit above physical_room_count.',
    `override_reason` STRING COMMENT 'Free-text or coded justification provided by the revenue manager when is_override is True. Documents the business rationale for deviating from the system recommendation (e.g., local event, competitive action, group displacement). Required for audit and RMS calibration.',
    `physical_room_count` STRING COMMENT 'Total number of physical rooms of this room type at the property, representing the hard capacity ceiling before overbooking allowances are applied. Used as the denominator for occupancy rate (OCC) calculations.',
    `rate_availability_source` STRING COMMENT 'Identifies the originating system or process that set the current rate and availability state for this control record. Supports data lineage, audit, and reconciliation between IDeaS G3 RMS, Sabre SynXis CRS, and Oracle OPERA PMS.. Valid values are `rms_automated|manual_override|channel_manager|pms_direct`',
    `sell_limit` STRING COMMENT 'Maximum number of rooms authorized to be sold for this room type on the stay date, inclusive of overbooking allowance. Set by the Revenue Management System and may exceed physical_room_count when overbooking is authorized. Enforced at the CRS and PMS booking engine.',
    `stay_date` DATE COMMENT 'The specific calendar date (night of stay) for which this inventory control record applies. Represents the primary dimension of the rate/availability grid alongside property, room type, and rate plan.',
    `system_recommended_value` DECIMAL(18,2) COMMENT 'The value recommended by the Revenue Management System (IDeaS G3 RMS or Infor EzRMS) prior to any manual override. Enables comparison between algorithmic recommendation and the applied control_value for yield optimization analysis and RMS model performance tracking.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this inventory control record was most recently modified in the source system. Used for incremental ETL processing, change detection, and audit trail maintenance in the Databricks Silver Layer.',
    `walk_compensation_type` STRING COMMENT 'Type of compensation offered to a walked guest when the walk_policy requires compensation. Governs the financial and loyalty implications of overbooking execution and is tracked for Guest Recovery Rate (GRR) and CPOR reporting.. Valid values are `cash_equivalent|room_upgrade|loyalty_points|voucher|partner_hotel`',
    `walk_policy` STRING COMMENT 'Defines the operational procedure to follow when a guest with a confirmed reservation cannot be accommodated due to overbooking (a walk). Determines whether the guest is walked to a partner hotel, upgraded, or compensated per AHLA guest relocation standards.. Valid values are `walk_and_compensate|walk_to_partner|upgrade_first|deny_walk`',
    CONSTRAINT pk_inventory_control PRIMARY KEY(`inventory_control_id`)
) COMMENT 'Inventory control records managing the complete room availability and pricing grid as applied in IDeaS G3 RMS. Encompasses hurdle rates, sell limits, overbooking levels, room type allotments, group blocks, and the resulting daily rate availability state per property, room type, and rate plan combination. Captures control type, room type, stay date, control value, system-recommended value, override indicator, overbooking policy parameters (max overbooking percentage, absolute cap, walk policy, compensation type, partner hotel agreements, approval authority), and real-time availability state (open/closed status, available inventory count, current BAR, minimum/maximum rates, last-updated timestamp). This is the SSOT for all inventory control decisions, overbooking policy configuration, and the rate/availability grid distributed via Sabre SynXis CRS for reservation fulfillment and channel distribution.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`performance_actuals` (
    `performance_actuals_id` BIGINT COMMENT 'Primary key for performance_actuals',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Actuals are compared against financial budgets for variance reporting, board presentations, and management performance evaluation against approved financial plans.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Campaign ROI reporting requires linking revenue performance actuals directly to the driving marketing campaign â€” a core hotel commercial reporting process. Enables direct measurement of campaign-attri',
    `competitive_set_id` BIGINT COMMENT 'Foreign key linking to revenue.competitive_set. Business justification: performance_actuals captures ARI, MPI, and RGI competitive index metrics. These metrics are computed relative to a specific competitive set (STR STAR Report). Adding competitive_set_id links each actu',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Loyalty promotion ROI reporting requires linking actual revenue performance to the promotion that drove it. Named process: promotion performance measurement and incremental revenue attribution. Revenu',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: RevPAR and room revenue actuals are tracked by cost center for departmental P&L, USALI reporting, and operational performance management.',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: performance_actuals.demand_forecast_rooms (INT) is a denormalized copy of the forecast rooms figure used for variance analysis. Adding demand_forecast_id links each daily actuals record to the specifi',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Daily actuals track which room nights and revenue came from specific event bookings for segment reporting. Required for event contribution analysis, MICE segment performance reporting, and group vs tr',
    `fiscal_period_id` BIGINT COMMENT 'Reference to the fiscal calendar period (month/quarter/year) to which this performance date belongs, enabling USALI-aligned financial period reporting and variance analysis against budget.',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: USALI-compliant departmental P&L reporting requires performance actuals to be tied to a specific F&B revenue center (e.g., restaurant, bar, banquet). Hotels report F&B RevPASH and GOP at revenue cente',
    `franchise_agreement_id` BIGINT COMMENT 'Foreign key linking to property.franchise_agreement. Business justification: Franchise fees (royalty, marketing, reservation fees) are calculated as percentages of revenue actuals per the franchise_agreement terms. Direct FK enables automated franchise fee computation and fran',
    `gss_score_id` BIGINT COMMENT 'Foreign key linking to experience.gss_score. Business justification: Revenue performance reporting includes GSS scores as a KPI alongside financial metrics for balanced scorecards (SALT program requirement). Daily flash reports show RevPAR and GSS togetherâ€”mandatory fo',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to property.hierarchy. Business justification: Performance actuals must be reported through the organizational hierarchy for regional and portfolio-level P&L rollups. Capturing hierarchy_id at the time of the performance record preserves the hiera',
    `hma_contract_id` BIGINT COMMENT 'Foreign key linking to finance.hma_contract. Business justification: HMA contracts include performance tests (RevPAR index, GOP thresholds) evaluated against actual results. Linking performance_actuals to hma_contract enables automated performance test calculations, ow',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Actual revenue performance posts to specific GL accounts for financial statement preparation, revenue recognition, and external financial reporting compliance.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Performance reporting breaks down revenue contribution by member tier for loyalty program ROI analysis. Business process: tier-level revenue attribution reporting required for evaluating loyalty progr',
    `ownership_entity_id` BIGINT COMMENT 'Foreign key linking to property.ownership_entity. Business justification: Performance actuals are reported to ownership entities for investor reporting, management fee calculations, and REIT compliance. Linking performance_actuals to ownership_entity enables direct owner-le',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Performance actuals track channel_direct_rooms and channel_ota_rooms as metrics but lack a proper FK to the channel entity. Linking to channel.channel enables channel-level RevPAR and ADR performance ',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Daily actuals track outlet-level F&B revenue for TRevPAR calculation and USALI reporting. Required for total property revenue reporting, GOP analysis, outlet performance attribution in consolidated fi',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Property performance actuals roll up to profit centers for consolidated financial reporting, ownership reporting, and portfolio-level performance analysis.',
    `program_id` BIGINT COMMENT 'Foreign key linking to experience.program. Business justification: Performance actuals must attribute ancillary and total revenue to specific experience programs for program ROI reporting. experience.program has revenue_impact_flag indicating this attribution is expe',
    `property_id` BIGINT COMMENT 'Reference to the property for which this daily revenue performance record is captured. Links to the property master entity in the Property domain.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Performance actuals are compared against seasonal plan targets (estimated_adr, estimated_occupancy_pct, rgi_target) from seasonal_calendar. Direct FK enables variance reporting between actual RevPAR a',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Daily performance actuals must be evaluated against the revenue strategy that was in effect on that performance_date. Linking performance_actuals to strategy enables strategy effectiveness measurement',
    `adr` DECIMAL(18,2) COMMENT 'Average Daily Rate in the propertys operating currency, calculated as total room revenue divided by rooms sold (excluding complimentary). Core KPI for STR STAR Report benchmarking, RGI, ARI, and MPI calculations.',
    `ancillary_revenue` DECIMAL(18,2) COMMENT 'Total ancillary revenue on the performance date from upsells, packages, resort fees, and add-on services not captured in departmental revenue lines. Supports total revenue and TRevPAR reporting.',
    `ari` DECIMAL(18,2) COMMENT 'Average Rate Index representing the propertys ADR performance relative to its competitive set, sourced from STR STAR Report. ARI > 1.0 indicates the property is achieving a rate premium over its comp set.',
    `budget_adr` DECIMAL(18,2) COMMENT 'Budgeted Average Daily Rate for the performance date. Used for ADR variance analysis against actuals in the DOR, revenue management reporting, and STR STAR Report benchmarking.',
    `budget_occupancy_rate` DECIMAL(18,2) COMMENT 'Budgeted occupancy rate for the performance date as a decimal (e.g., 0.7500 = 75.00%). Used for occupancy variance analysis against actuals in the DOR and revenue management reporting.',
    `budget_room_revenue` DECIMAL(18,2) COMMENT 'Budgeted room revenue for the performance date as approved in the annual operating budget. Used for variance analysis against actual room revenue in the DOR and ownership reporting.',
    `budget_total_revenue` DECIMAL(18,2) COMMENT 'Budgeted total property revenue for the performance date as approved in the annual operating budget. Used for total revenue variance analysis in the DOR and ownership reporting.',
    `channel_direct_rooms` STRING COMMENT 'Number of rooms sold through direct channels (brand website, call center, walk-in) on the performance date. Supports direct vs. indirect channel mix analysis and cost-of-acquisition reporting.',
    `channel_ota_rooms` STRING COMMENT 'Number of rooms sold through Online Travel Agency (OTA) channels (e.g., Expedia, Booking.com) on the performance date. Supports channel distribution mix analysis and OTA commission cost management.',
    `cpor` DECIMAL(18,2) COMMENT 'Cost Per Occupied Room on the performance date, calculated as total rooms department operating expenses divided by rooms sold. Measures operational efficiency of the rooms department per USALI.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this performance actual record was first created in the data lakehouse Silver layer. Supports audit trail and data lineage requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this performance record (e.g., USD, EUR, GBP). Enables multi-currency property portfolio reporting and consolidation.. Valid values are `^[A-Z]{3}$`',
    `ebitda_contribution` DECIMAL(18,2) COMMENT 'Property-level EBITDA contribution on the performance date, representing operating earnings before interest, taxes, depreciation, and amortization. Used for ownership reporting, asset valuation, and management contract performance measurement.',
    `fb_revenue` DECIMAL(18,2) COMMENT 'Total Food and Beverage revenue generated on the performance date across all F&B outlets (restaurants, bars, banquets, in-room dining). Sourced from Oracle Hospitality MICROS POS and reconciled against SAP S/4HANA. Included in TRevPAR calculation per USALI.',
    `gop` DECIMAL(18,2) COMMENT 'Gross Operating Profit on the performance date, calculated as total operated department revenue minus total operated department expenses per USALI. Key profitability metric for ownership reporting and management contracts.',
    `goppar` DECIMAL(18,2) COMMENT 'Gross Operating Profit Per Available Room in the propertys operating currency, calculated as GOP divided by rooms available. Measures overall property profitability efficiency. Core KPI for ownership reporting and management fee calculations.',
    `is_reconciled` BOOLEAN COMMENT 'Indicates whether this daily performance actual record has been reconciled between Oracle OPERA PMS and SAP S/4HANA General Ledger. True = reconciled and approved for reporting; False = pending reconciliation. Supports financial close and SOX controls.',
    `miscellaneous_income` DECIMAL(18,2) COMMENT 'Total miscellaneous and rental income on the performance date including rentals, commissions, and other non-departmental income per USALI non-operating income classification.',
    `mpi` DECIMAL(18,2) COMMENT 'Market Penetration Index representing the propertys occupancy performance relative to its competitive set, sourced from STR STAR Report. MPI > 1.0 indicates the property is capturing more than its fair share of market occupancy.',
    `occupancy_rate` DECIMAL(18,2) COMMENT 'Daily occupancy rate expressed as a decimal (e.g., 0.8250 = 82.50%), calculated as rooms sold divided by rooms available. Core KPI for the STR STAR Report, DOR, and ownership reporting. Stored as a raw ratio; display layer applies percentage formatting.',
    `parking_revenue` DECIMAL(18,2) COMMENT 'Total parking revenue generated on the performance date from valet, self-park, and garage operations. Classified under other operated departments per USALI and included in TRevPAR.',
    `performance_date` DATE COMMENT 'The calendar date (business date) for which this revenue performance actual record applies. Represents the stay date or operating day used in the Daily Operations Report (DOR) and all KPI calculations.',
    `prior_year_revpar` DECIMAL(18,2) COMMENT 'RevPAR for the same calendar date in the prior year. Used for year-over-year (YOY) variance analysis in the DOR, STR STAR Report benchmarking, and ownership reporting.',
    `record_status` STRING COMMENT 'Lifecycle status of this performance actual record indicating whether figures are preliminary (intra-day), final (end-of-day close), adjusted (post-close correction), or closed (period-locked). Supports audit and reconciliation workflows.. Valid values are `draft|preliminary|final|adjusted|closed`',
    `revpar` DECIMAL(18,2) COMMENT 'Revenue Per Available Room in the propertys operating currency, calculated as ADR multiplied by occupancy rate (or total room revenue divided by rooms available). Primary rooms revenue KPI for ownership reporting, STR STAR Report, and RGI benchmarking.',
    `rgi` DECIMAL(18,2) COMMENT 'Revenue Generation Index representing the propertys RevPAR performance relative to its competitive set, sourced from STR STAR Report. RGI > 1.0 indicates the property is outperforming its comp set. Core competitive benchmarking KPI.',
    `rooms_available` STRING COMMENT 'Total number of rooms available for sale on the performance date after deducting out-of-order (OOO) and out-of-service (OOS) rooms. Denominator for Occupancy Rate (OCC) and RevPAR calculations per USALI and STR STAR Report standards.',
    `rooms_complimentary` STRING COMMENT 'Number of rooms occupied on a complimentary (no-charge) basis on the performance date. Tracked separately per USALI for accurate ADR and revenue reporting, as complimentary rooms are excluded from ADR calculation.',
    `rooms_out_of_order` STRING COMMENT 'Number of rooms designated as out-of-order (OOO) on the performance date due to maintenance, renovation, or damage. Excluded from rooms available per USALI inventory standards.',
    `rooms_sold` STRING COMMENT 'Total number of rooms occupied (sold) on the performance date, including complimentary rooms. Used to calculate Occupancy Rate (OCC) and Average Daily Rate (ADR) per USALI standards.',
    `segment_contract_rooms` STRING COMMENT 'Number of rooms sold under negotiated contract rates (airline crew, long-stay corporate contracts) on the performance date. Supports contract segment revenue analysis and channel mix reporting.',
    `segment_group_rooms` STRING COMMENT 'Number of rooms sold to group accounts (MICE, corporate groups, tour groups) on the performance date. Supports group vs. transient mix analysis and group revenue contribution reporting per USALI.',
    `segment_transient_rooms` STRING COMMENT 'Number of rooms sold to transient (individual/FIT) guests on the performance date. Supports segment-level revenue analysis and channel mix reporting per USALI market segmentation standards.',
    `source_system_code` STRING COMMENT 'Identifies the operational system of record from which this performance actual record was sourced or reconciled (e.g., Oracle OPERA PMS for rooms data, SAP S/4HANA for financial totals). Supports data lineage and reconciliation audits.. Valid values are `OPERA_PMS|SAP_S4HANA|IDEASS_G3|INFOR_EZRMS|MANUAL`',
    `spa_revenue` DECIMAL(18,2) COMMENT 'Total spa and wellness revenue generated on the performance date. Included in total property revenue and TRevPAR calculation per USALI other operated departments classification.',
    `total_property_revenue` DECIMAL(18,2) COMMENT 'Total gross revenue across all operated departments and income streams on the performance date (rooms + F&B + spa + parking + other operated departments + miscellaneous + ancillary). Denominator basis for TRevPAR. Reconciled against SAP S/4HANA GL per USALI.',
    `total_room_revenue` DECIMAL(18,2) COMMENT 'Total gross room revenue generated on the performance date across all rate plans and channels, before deductions. Sourced from Oracle OPERA PMS and reconciled against SAP S/4HANA GL. Numerator for ADR and RevPAR calculations per USALI.',
    `trevpar` DECIMAL(18,2) COMMENT 'Total Revenue Per Available Room in the propertys operating currency, calculated as total property revenue divided by rooms available. Measures total revenue productivity of the property beyond rooms. Core KPI for ownership and management reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this performance actual record was last modified, including post-close adjustments or reconciliation corrections. Supports audit trail and change tracking.',
    CONSTRAINT pk_performance_actuals PRIMARY KEY(`performance_actuals_id`)
) COMMENT 'Daily revenue performance actuals at the property level capturing all revenue streams aligned to USALI departmental reporting. Includes room revenue metrics (ADR, OCC, RevPAR, rooms sold, rooms available, total room revenue) and total property revenue metrics (F&B revenue, spa revenue, parking, other operated departments, miscellaneous income, ancillary revenue, TRevPAR, GOPPAR, CPOR, GOP, EBITDA contribution). Sourced from Oracle OPERA PMS and SAP S/4HANA, reconciled against USALI standards. This is the single authoritative record for all daily revenue performance â€” both rooms and total revenue â€” used for the Daily Operations Report (DOR), ownership reporting, TRevPAR/GOPPAR calculation, and variance analysis against budget.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`market_segment` (
    `market_segment_id` BIGINT COMMENT 'Unique surrogate identifier for the market segment record. Primary key for the market_segment data product in the revenue domain. Role classification: MASTER_RESOURCE â€” this entity represents a classification resource used across revenue, reservation, and channel domains.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Market segments map to typical loyalty tiers for segmentation alignment and forecasting. Business process: aligning revenue management segments with loyalty tier definitions for consistent guest class',
    `ada_accommodation_typical` BOOLEAN COMMENT 'Indicates whether guests in this market segment typically require ADA (Americans with Disabilities Act) accessible accommodations. Relevant for government, medical, and certain group segments. Informs room inventory allocation and accessibility compliance reporting.',
    `avg_lead_time_days` STRING COMMENT 'Average number of days between booking date and arrival date for this market segment. Key input for demand forecasting in IDeaS G3 RMS and Infor EzRMS. Segments with short lead times (e.g., OTA last-minute) require different yield strategies than long-lead corporate or group segments. Represents the MEASUREMENT_OR_VALUE for this resource.',
    `avg_length_of_stay_nights` DECIMAL(18,2) COMMENT 'Average number of nights guests in this segment stay per booking (ALOS â€” Average Length of Stay). Used in revenue management for LOS (Length of Stay) restriction optimization, demand forecasting, and RevPAR (Revenue Per Available Room) modeling in IDeaS G3 RMS.',
    `cancellation_propensity` STRING COMMENT 'Qualitative classification of the historical cancellation rate tendency for this market segment. Informs overbooking strategy, no-show reserve calculations, and revenue protection policies in IDeaS G3 RMS. High-propensity segments (e.g., OTA flexible rate) require higher overbooking buffers.. Valid values are `very_low|low|medium|high|very_high`',
    `channel_affinity` STRING COMMENT 'Primary distribution channel through which this market segment predominantly books. Drives channel strategy, OTA (Online Travel Agency) commission management, and GDS (Global Distribution System) rate loading decisions in Sabre SynXis CRS. Used for channel mix analysis and cost-of-acquisition reporting. [ENUM-REF-CANDIDATE: direct|ota|gds|voice|group|wholesale|other â€” 7 candidates stripped; promote to reference product]',
    `commission_eligible` BOOLEAN COMMENT 'Indicates whether bookings in this segment are subject to travel agent or OTA commission payments. Direct corporate and government segments are typically non-commissionable; OTA and GDS segments carry commission obligations. Drives accounts payable commission processing in SAP S/4HANA.',
    `commission_rate_pct` DECIMAL(18,2) COMMENT 'Standard commission rate percentage applicable to bookings in this segment when commission_eligible is true. Expressed as a percentage of room revenue (e.g., 10.00 for 10%). Used for cost-of-acquisition analysis, OTA contract management, and CPOR (Cost Per Occupied Room) calculations. Confidential as it reflects contracted commercial terms.',
    `contribution_margin_tier` STRING COMMENT 'Classification of the segments typical contribution margin profile relative to other segments. Reflects net revenue after channel commissions, OTA fees, GDS fees, and loyalty redemption costs. Premium tiers (e.g., direct corporate) yield higher GOP (Gross Operating Profit) than low-margin OTA or wholesale segments. Used in GOPPAR analysis.. Valid values are `premium|standard|value|low_margin`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this market segment record was first created in the enterprise data lakehouse. Supports data lineage, audit trail, and record provenance tracking. Aligns with RECORD_AUDIT_CREATED requirement for MASTER_RESOURCE entities.',
    `crs_segment_code` STRING COMMENT 'The segment code as configured in Sabre SynXis CRS for central reservations and channel distribution. Used for rate plan distribution, availability controls, and channel-level segment reporting. Enables cross-system segment reconciliation.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `demand_pattern` STRING COMMENT 'Classification of the temporal demand pattern exhibited by this market segment. Corporate transient segments typically show weekday concentration; leisure segments show weekend and seasonal peaks; event-driven segments spike around MICE (Meetings Incentives Conferences Exhibitions) events. Used in Infor EzRMS demand forecasting.. Valid values are `weekday|weekend|seasonal|year_round|event_driven`',
    `effective_from` DATE COMMENT 'Date from which this market segment definition becomes active and available for use in reservations, rate plans, and revenue reporting. Supports temporal validity management for segment taxonomy changes aligned with fiscal year or STR reporting period updates.',
    `effective_until` DATE COMMENT 'Date after which this market segment definition is no longer active. Null indicates an open-ended segment with no planned expiry. Supports segment lifecycle management and historical reporting continuity when segment taxonomies are revised.',
    `gdpr_data_subject_applicable` BOOLEAN COMMENT 'Indicates whether guest data associated with bookings in this market segment is subject to GDPR data subject rights (right to erasure, portability, access). Relevant for segments involving EU/EEA guests. Drives data retention and anonymization policies in the data lakehouse.',
    `gds_eligible` BOOLEAN COMMENT 'Indicates whether rates for this market segment are distributed through GDS (Global Distribution System) channels such as Amadeus, Sabre, and Travelport. Controls rate loading and availability display in Sabre SynXis CRS for GDS-connected travel agencies.',
    `group_block_eligible` BOOLEAN COMMENT 'Indicates whether this market segment supports group room block reservations. Group-eligible segments (e.g., MICE, sports groups, tour groups) require group block management in Oracle OPERA PMS and Delphi by Amadeus for BEO (Banquet Event Order) coordination.',
    `hierarchy_level` STRING COMMENT 'Numeric level of this segment within the market segment hierarchy. Level 1 represents top-level categories (e.g., Transient, Group); Level 2 represents sub-categories (e.g., Corporate, Leisure); Level 3 represents granular segments (e.g., Corporate Negotiated, Leisure OTA). Used for hierarchical roll-up in revenue reporting.',
    `is_internal_use_only` BOOLEAN COMMENT 'Indicates whether this market segment is for internal reporting and analytics purposes only and should not be exposed to guests, OTA partners, or external distribution channels. Internal segments (e.g., complimentary, house use, employee rate) are excluded from external rate distribution in Sabre SynXis CRS.',
    `loyalty_eligible` BOOLEAN COMMENT 'Indicates whether bookings under this market segment are eligible to earn loyalty program points and benefits. Wholesale, crew, and certain contracted segments may be excluded from loyalty accrual per program rules. Drives loyalty point calculation logic in Salesforce CRM loyalty management.',
    `market_segment_description` STRING COMMENT 'Detailed narrative description of the market segment, including its defining characteristics, typical guest profile, booking behavior, and applicable rate strategies. Used for training, documentation, and business glossary alignment across revenue management, reservations, and sales teams.',
    `market_segment_status` STRING COMMENT 'Current lifecycle status of the market segment record. Active segments are available for rate plan assignment, reservation coding, and revenue reporting. Inactive or deprecated segments are retained for historical analysis but excluded from new bookings. Aligns with MASTER_RESOURCE LIFECYCLE_STATUS requirement.. Valid values are `active|inactive|deprecated|pending_review`',
    `min_rate_override_allowed` BOOLEAN COMMENT 'Indicates whether revenue managers are permitted to override the minimum rate floor for this segment. Restricting overrides for high-value segments (e.g., LRA corporate) protects rate integrity. Configurable in IDeaS G3 RMS inventory controls and Oracle OPERA PMS rate management.',
    `negotiated_rate_required` BOOLEAN COMMENT 'Indicates whether bookings in this segment require a pre-negotiated rate agreement (e.g., corporate account rate, government per diem, airline crew contract). When true, a valid rate agreement must exist before reservations can be accepted at segment rates in Oracle OPERA PMS.',
    `no_show_propensity` STRING COMMENT 'Qualitative classification of the historical no-show rate tendency for this market segment. Distinct from cancellation propensity â€” no-shows occur without prior cancellation and have different revenue recovery implications. Used in overbooking model calibration within IDeaS G3 RMS.. Valid values are `very_low|low|medium|high|very_high`',
    `ota_eligible` BOOLEAN COMMENT 'Indicates whether rates for this market segment are distributed through OTA (Online Travel Agency) channels such as Expedia, Booking.com, and Hotels.com. Controls channel availability in Sabre SynXis CRS and impacts OTA commission cost tracking.',
    `pci_scope` BOOLEAN COMMENT 'Indicates whether payment card data associated with bookings in this segment falls within PCI DSS scope. Segments with direct card-present or card-not-present transactions require PCI-compliant data handling. Drives data masking and tokenization requirements in the lakehouse.',
    `pms_segment_code` STRING COMMENT 'The segment code as configured in Oracle OPERA PMS. Used for reservation coding, folio routing, and rate plan assignment at the property level. Enables reconciliation between the enterprise data lakehouse and the operational PMS source system.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `price_sensitivity` STRING COMMENT 'Classification of the segments sensitivity to rate changes. Inelastic segments (e.g., airline crew, government contracted) book regardless of rate fluctuations. Highly elastic segments (e.g., leisure OTA) respond strongly to price changes. Drives DRR (Dynamic Rate Rule) configuration in IDeaS G3 RMS.. Valid values are `inelastic|low|moderate|high|very_high`',
    `rate_plan_category` STRING COMMENT 'Classification of the rate plan type typically associated with this segment. BAR (Best Available Rate) for transient leisure, negotiated for corporate accounts, LRA (Last Room Availability) for top-tier corporate, NRR (Non-Refundable Rate) for advance purchase segments. Drives rate loading in Oracle OPERA PMS and Sabre SynXis CRS. [ENUM-REF-CANDIDATE: bar|negotiated|lra|nrr|wholesale|package|complimentary â€” 7 candidates stripped; promote to reference product]',
    `revenue_bucket` STRING COMMENT 'Primary revenue category associated with this market segment for TRevPAR (Total Revenue Per Available Room) and USALI departmental reporting. Rooms-focused segments contribute primarily to rooms revenue; MICE segments contribute across rooms, F&B (Food and Beverage), and events revenue buckets.. Valid values are `rooms|food_beverage|events|ancillary|total`',
    `rms_segment_code` STRING COMMENT 'The segment code as configured in IDeaS G3 RMS or Infor EzRMS. Used for demand forecasting, pricing optimization, and inventory control at the segment level. May differ from PMS segment code due to system-specific taxonomy requirements.. Valid values are `^[A-Z0-9_]{1,20}$`',
    `segment_category` STRING COMMENT 'High-level classification grouping the segment into a primary demand category. Drives pricing strategy, channel allocation, and revenue reporting roll-ups. Aligns with STR segment category definitions used in STAR Report benchmarking. [ENUM-REF-CANDIDATE: transient|group|contract|wholesale|ota|corporate|government|leisure|crew|airline â€” promote to reference product]',
    `segment_code` STRING COMMENT 'Short alphanumeric code uniquely identifying the market segment, used as the externally-known business identifier across Oracle OPERA PMS, IDeaS G3 RMS, Sabre SynXis CRS, and Infor EzRMS. Examples: CORP, TRANS, LEIS, OTA, GRP, GOVT, CREW. Aligns with STR segment code taxonomy for benchmarking and STAR Report mapping.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `segment_name` STRING COMMENT 'Full descriptive name of the market segment as displayed in reporting, dashboards, and revenue management systems. Examples: Corporate Negotiated, Leisure Transient, Online Travel Agency, Government/Military, Group Meetings. Used as the IDENTITY_LABEL for this resource entity.',
    `segment_type` STRING COMMENT 'Secondary classification distinguishing whether the segment represents individual (FIT â€” Free Independent Traveler) bookings, group blocks, negotiated corporate accounts, wholesale/tour operator contracts, or consortia arrangements. Used in IDeaS G3 RMS for demand segmentation and pricing strategy.. Valid values are `individual|group|negotiated|wholesale|consortia`',
    `sort_order` STRING COMMENT 'Numeric value controlling the display sequence of market segments in reports, dashboards, and system configuration screens. Ensures consistent ordering in Oracle OPERA PMS segment lists, IDeaS G3 RMS segment configuration, and BI reporting tools.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this market segment definition originated. Enables data lineage tracking and reconciliation between Oracle OPERA PMS, IDeaS G3 RMS, Sabre SynXis CRS, and Infor EzRMS segment taxonomies in the Silver Layer lakehouse.. Valid values are `opera_pms|ideas_g3_rms|sabre_synxis_crs|infor_ezrms|manual`',
    `str_segment_code` STRING COMMENT 'The official STR (Smith Travel Research) segment code used for competitive benchmarking and STAR Report alignment. Enables mapping of internal segment definitions to the industry-standard STR taxonomy for RGI (Revenue Generation Index), MPI (Market Penetration Index), and ARI (Average Rate Index) calculations.. Valid values are `^[A-Z0-9]{2,10}$`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this market segment record was last modified. Tracks configuration changes to segment definitions, status updates, and taxonomy revisions. Essential for change data capture (CDC) in ETL pipelines feeding IDeaS G3 RMS and Infor EzRMS.',
    `usali_segment_code` STRING COMMENT 'The USALI (Uniform System of Accounts for the Lodging Industry) standardized segment code used for financial reporting and departmental P&L allocation. Ensures consistency in GOP (Gross Operating Profit), NOI (Net Operating Income), and EBITDA reporting across properties and for external financial audits under GAAP/IFRS.. Valid values are `^[A-Z0-9_]{2,15}$`',
    CONSTRAINT pk_market_segment PRIMARY KEY(`market_segment_id`)
) COMMENT 'Master classification of revenue market segments used for demand analysis, pricing strategy, and performance reporting. Defines segment code, segment name, segment category (transient, group, contract, wholesale, OTA, corporate, government, leisure, crew, airline), contribution margin profile, booking behavior characteristics, average lead time, and cancellation propensity. SSOT for market segment taxonomy aligned to STR segment definitions and used across revenue, reservation, and channel domains.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`competitive_set` (
    `competitive_set_id` BIGINT COMMENT 'Primary key for competitive_set',
    `brand_id` BIGINT COMMENT 'Foreign key linking to marketing.brand. Business justification: Competitive sets are defined by brand tier comparability â€” revenue managers scope STR comp sets to matching brand tiers. Brand alignment is a required input for comp set approval and STR submission. A',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to property.hierarchy. Business justification: Competitive sets are defined at market and geographic levels that align with hierarchy nodes (geographic_region, str_market_name). Linking competitive_set to hierarchy enables portfolio-level STR benc',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: competitive_set.market_segment (STRING) is a denormalized reference to the market segment focus of the competitive set. Adding market_segment_id normalizes this to the authoritative market_segment rec',
    `property_id` BIGINT COMMENT 'Identifier of the subject property (the home property) that owns this competitive set definition. Links to the property master record in the Property domain.',
    `advance_purchase_window_days` STRING COMMENT 'The booking lead time window in days used for rate shopping comparisons within this competitive set (e.g., 0 = same-day, 7 = 7-day advance, 30 = 30-day advance). Ensures rate intelligence is captured at consistent booking horizons for fair ADR comparison.',
    `approval_date` DATE COMMENT 'The date on which the competitive set definition was formally approved by the revenue management authority. Supports audit trail requirements for comp set governance and STR STAR Report submission integrity.',
    `approved_by` STRING COMMENT 'Name or identifier of the revenue management leader or Director of Revenue who approved this competitive set definition. Required for governance and audit trail of comp set changes that affect STR STAR Report submissions.',
    `ari_target` DECIMAL(18,2) COMMENT 'The Average Rate Index (ARI) target threshold for this competitive set. ARI = Property ADR / Comp Set ADR. A value above 1.00 indicates the property targets a higher ADR than the competitive set average. Drives BAR pricing strategy in IDeaS G3 RMS.',
    `benchmarking_currency_code` STRING COMMENT 'ISO 4217 three-letter currency code used for normalizing ADR, RevPAR, and TRevPAR benchmarking metrics across all properties in the competitive set (e.g., USD, EUR, GBP). Ensures consistent monetary comparison in STR STAR Report analysis.. Valid values are `^[A-Z]{3}$`',
    `competitive_set_name` STRING COMMENT 'Human-readable name assigned to the competitive set (e.g., Downtown Luxury Primary Set, Airport Corridor Secondary Set). Used in Infor EzRMS and STR STAR Report submissions to identify the grouping.',
    `competitive_set_status` STRING COMMENT 'Current lifecycle status of the competitive set. active sets are used in live RMS benchmarking and STR reporting; inactive sets are suspended; pending_approval awaits revenue management sign-off; archived are historical sets retained for trend analysis.. Valid values are `active|inactive|pending_approval|archived`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this competitive set record was first created in the system. Supports audit trail, data lineage, and change history tracking in the Databricks Silver Layer. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `demand_segment_focus` STRING COMMENT 'The primary guest demand segment this competitive set is designed to benchmark. transient focuses on FIT (Free Independent Traveler) and leisure; group focuses on MICE (Meetings, Incentives, Conferences, Exhibitions) and group blocks; contract focuses on negotiated corporate rates; all_segments covers the full mix.. Valid values are `transient|group|contract|all_segments`',
    `effective_from` DATE COMMENT 'The date from which this competitive set definition becomes active and is used for STR STAR Report benchmarking, RGI, MPI, and ARI calculations. Aligns with STR reporting period start.',
    `effective_until` DATE COMMENT 'The date on which this competitive set definition expires and is no longer used for active benchmarking. Null indicates an open-ended, currently active set. Supports historical trend analysis when comp set membership changes.',
    `geographic_market` STRING COMMENT 'The geographic market or submarket in which the competitive set operates (e.g., Manhattan Midtown, Chicago OHare Corridor, Miami Beach). Aligns with STR market definitions used for Market Penetration Index (MPI) calculations.',
    `ideass_comp_set_code` STRING COMMENT 'The competitive set reference code as configured in IDeaS G3 RMS for pricing strategy alignment. Enables synchronization of comp set definitions between Infor EzRMS benchmarking and IDeaS G3 RMS dynamic pricing rules (DRR) and BAR optimization.',
    `is_str_submitted` BOOLEAN COMMENT 'Indicates whether this competitive set has been formally submitted to STR (Smith Travel Research) for STAR Report benchmarking. True means the set is registered with STR and receives STAR Report data; False means it is an internal-only comp set.',
    `last_reviewed_date` DATE COMMENT 'The most recent date on which the competitive set membership and parameters were reviewed by the revenue management team. Best practice requires annual or semi-annual review to ensure comp set relevance as market conditions evolve.',
    `los_benchmark_nights` STRING COMMENT 'The standard Length of Stay (LOS) in nights used as the basis for rate comparison within this competitive set. Typically set to 1 night for transient benchmarking. Used to normalize ADR comparisons across properties with different LOS mix.',
    `market_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary geographic market for this competitive set (e.g., USA, GBR, DEU). Used for multi-national portfolio benchmarking and currency normalization in revenue performance reporting.. Valid values are `^[A-Z]{3}$`',
    `max_room_count` STRING COMMENT 'Maximum number of guestrooms a competitor property may have to qualify for inclusion in this competitive set. Used alongside min_room_count to define the acceptable size range for comp set membership.',
    `member_count` STRING COMMENT 'Total number of competitor properties currently included in this competitive set. STR STAR Report typically requires a minimum of 3 and maximum of 10 competitor properties for statistically valid benchmarking. Derived from the comp set membership roster but stored here for quick reference.',
    `min_room_count` STRING COMMENT 'Minimum number of guestrooms a competitor property must have to qualify for inclusion in this competitive set. Ensures size comparability for RevPAR and occupancy benchmarking. Typically aligned with the subject propertys room count range.',
    `mpi_target` DECIMAL(18,2) COMMENT 'The Market Penetration Index (MPI) target threshold for this competitive set. MPI = Property Occupancy Rate / Comp Set Occupancy Rate. A value above 1.00 indicates the property targets higher occupancy than the competitive set average. Used in revenue strategy planning.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of this competitive set definition. Ensures comp set membership remains current and aligned with market dynamics. Triggers a review workflow in the Revenue Management System.',
    `notes` STRING COMMENT 'Free-text field for revenue management team annotations regarding this competitive set, such as rationale for competitor inclusion/exclusion, market context, or pending changes. Not used in automated benchmarking calculations.',
    `primary_benchmarking_metric` STRING COMMENT 'The primary Key Performance Indicator (KPI) used to evaluate competitive performance for this comp set. Options include RevPAR (Revenue Per Available Room), ADR (Average Daily Rate), Occupancy Rate (OCC), TRevPAR (Total Revenue Per Available Room), or GOPPAR (Gross Operating Profit Per Available Room).. Valid values are `revpar|adr|occupancy|trevpar|goppar`',
    `property_type_filter` STRING COMMENT 'Filter defining the property service type composition of this competitive set. Ensures benchmarking is conducted against properties of comparable service level and amenity offering. Aligns with AHLA property classification standards.. Valid values are `full_service|select_service|extended_stay|resort|boutique|all_types`',
    `rate_shop_frequency` STRING COMMENT 'Frequency at which competitor rates are retrieved from OTA and GDS channels for properties in this competitive set. Drives the cadence of dynamic pricing adjustments in IDeaS G3 RMS. Only applicable when rate_shopping_enabled is True.. Valid values are `real_time|hourly|daily|weekly`',
    `rate_shopping_enabled` BOOLEAN COMMENT 'Indicates whether automated rate shopping (competitive rate intelligence) is active for this competitive set. When True, the RMS retrieves competitor BAR rates from OTA channels and GDS for dynamic pricing decisions. When False, only STR STAR Report data is used.',
    `rgi_target` DECIMAL(18,2) COMMENT 'The Revenue Generation Index (RGI) target threshold set by the revenue management team for this competitive set. RGI = Property RevPAR / Comp Set RevPAR. A target above 1.00 indicates the property aims to outperform the comp set. Used in IDeaS G3 RMS and Infor EzRMS for performance goal-setting.',
    `rms_comp_set_reference` STRING COMMENT 'The native competitive set identifier as stored in the Revenue Management System (Infor EzRMS or IDeaS G3 RMS). Used for cross-system reconciliation and data lineage tracing between the lakehouse Silver Layer and the operational RMS.',
    `set_type` STRING COMMENT 'Classification of the competitive set indicating its strategic purpose. primary is the main STR STAR Report comp set; secondary is an alternate benchmarking group; custom is an ad-hoc internal set; str_defined is a set defined by STR directly; internal is used for internal rate intelligence only.. Valid values are `primary|secondary|custom|str_defined|internal`',
    `source_system` STRING COMMENT 'The operational system of record from which this competitive set definition was originated or last updated. Supports data lineage tracking in the Databricks Silver Layer. infor_ezrms = Infor EzRMS; ideass_g3 = IDeaS G3 RMS; manual = manually entered; str_direct = received directly from STR.. Valid values are `infor_ezrms|ideass_g3|manual|str_direct`',
    `str_comp_set_code` STRING COMMENT 'The unique alphanumeric code assigned by STR (Smith Travel Research) to identify this competitive set in the STAR Report system. Required for submitting and retrieving benchmarking data from STR. Maps directly to the STR comp set identifier in Infor EzRMS.',
    `str_market_code` STRING COMMENT 'The STR-assigned market code identifying the geographic market in which this competitive set is benchmarked. Used to retrieve market-level aggregates for MPI calculation and to align with STR STAR Report market definitions.',
    `str_report_frequency` STRING COMMENT 'Frequency at which STR STAR Report data is received and processed for this competitive set. Determines the cadence of RGI, MPI, and ARI metric refreshes in the Revenue Management System.. Valid values are `daily|weekly|monthly`',
    `str_submarket_code` STRING COMMENT 'The STR-assigned submarket code for more granular geographic benchmarking within a broader STR market. Used when the competitive set operates in a distinct submarket (e.g., airport vs. downtown within the same city market).',
    `str_submission_date` DATE COMMENT 'The date on which this competitive set was submitted to STR for STAR Report registration. Relevant only when is_str_submitted is True. Used for audit and compliance tracking of STR data agreements.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this competitive set record was most recently modified. Used to detect changes in comp set definitions, track membership updates, and support incremental ETL processing in the Databricks Silver Layer. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_competitive_set PRIMARY KEY(`competitive_set_id`)
) COMMENT 'Master definition of competitive hotel sets used for STR STAR Report benchmarking and competitive rate intelligence. Captures comp set name, property membership, comp set type (primary, secondary, custom), effective date range, and STR property codes. Managed in Infor EzRMS and used to calculate RGI (Revenue Generation Index), MPI (Market Penetration Index), and ARI (Average Rate Index).';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`group_evaluation` (
    `group_evaluation_id` BIGINT COMMENT 'Unique surrogate identifier for each group business evaluation record generated by IDeaS G3 RMS. Primary key for the group_evaluation data product in the Silver Layer lakehouse.',
    `account_id` BIGINT COMMENT 'Identifier of the corporate account, travel agency, or group organizer account associated with this group inquiry, as maintained in Salesforce CRM and Oracle OPERA PMS AR module.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Group displacement analysis must account for active loyalty promotions during the groups stay dates, as promotions affect transient demand and displacement cost. Named process: promotion-adjusted gro',
    `booking_source_id` BIGINT COMMENT 'Foreign key linking to channel.booking_source. Business justification: Group evaluations originate from specific booking sources (group desk, travel agent, OTA group portal). FK enables channel-level group business analysis, commission calculation for group bookings, and',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Group evaluations compare displacement cost and net revenue impact against the propertys financial budget. Revenue managers explicitly reference budgeted transient ADR and room revenue when making gr',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Group RFPs often originate from marketing campaigns targeting corporate/SMIC segments. Linking the campaign helps measure campaign effectiveness in driving qualified group leads and conversion rates.',
    `campaign_offer_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign_offer. Business justification: Group sales evaluations frequently reference specific campaign offers (e.g., a corporate group requesting a promotional rate tied to an active offer). Revenue managers must validate offer eligibility ',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Group evaluations are channel-specific â€” the proposed group rate, displacement analysis, and commission terms depend on which distribution channel the group inquiry came through. FK enables channel-le',
    `competitive_set_id` BIGINT COMMENT 'Foreign key linking to revenue.competitive_set. Business justification: group_evaluation.rgi_benchmark (DECIMAL) is a competitive index metric used in group displacement analysis. This metric is computed relative to a specific competitive set. Adding competitive_set_id li',
    `member_id` BIGINT COMMENT 'Foreign key linking to loyalty.member. Business justification: Group bookings often involve loyalty members as decision-makers, influencing pricing decisions. Business process: tracking member-led group inquiries for loyalty credit attribution and personalized gr',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: group_evaluation.demand_forecast_occupancy_pct (DECIMAL) is a denormalized copy of the projected occupancy from the demand forecast used in displacement cost calculations. Adding demand_forecast_id li',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Group evaluation in revenue management directly produces an accepted event booking. Revenue managers track which evaluation led to which confirmed booking for displacement analysis, conversion reporti',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Group evaluations assess displacement cost and net revenue impact within a fiscal period context. Revenue managers and finance teams review group business decisions against period budgets; this FK ena',
    `function_space_id` BIGINT COMMENT 'Foreign key linking to event.function_space. Business justification: Group displacement analysis requires knowing which function spaces are requested to calculate total revenue displacement (rooms + space rental). Revenue managers evaluate function space availability a',
    `inquiry_id` BIGINT COMMENT 'Foreign key linking to event.inquiry. Business justification: Group evaluations are initiated from event inquiries in the standard MICE sales-to-revenue workflow. Linking evaluation to inquiry enables lead-to-evaluation conversion tracking, inquiry qualification',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Group booking decisions impact revenue recognition and require GL account mapping for group revenue tracking, displacement cost accounting, and profitability analysis.',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Group business evaluations are classified by market segment (e.g., Group Corporate, Group Association, Group SMERF). Adding market_segment_id links each group evaluation to its market segment classifi',
    `meeting_space_id` BIGINT COMMENT 'Foreign key linking to property.meeting_space. Business justification: Hotel group evaluations assess both room block revenue and meeting space requirements together. Linking group_evaluation to meeting_space enables total group revenue assessment including space rental ',
    `negotiated_rate_id` BIGINT COMMENT 'Foreign key linking to revenue.revenue_negotiated_rate. Business justification: Group evaluations for corporate or wholesale accounts may reference an existing negotiated rate agreement as the basis for the proposed group rate. Adding revenue_negotiated_rate_id links the group ev',
    `property_id` BIGINT COMMENT 'Identifier of the hotel or resort property for which the group evaluation is being conducted. Links to the property master record in the Property domain.',
    `proposal_id` BIGINT COMMENT 'Foreign key linking to event.proposal. Business justification: Revenue managers evaluate group business by reviewing the sales proposal to assess displacement cost and yield impact. The group evaluation record must reference the originating proposal to support MI',
    `banquet_menu_package_id` BIGINT COMMENT 'Foreign key linking to fnb.banquet_menu_package. Business justification: During group evaluation, revenue managers assess the proposed banquet menu package to calculate total group F&B revenue before a BEO is created. The existing primary_banquet_event_order_id covers post',
    `rate_availability_id` BIGINT COMMENT 'Foreign key linking to revenue.rate_availability. Business justification: Group evaluations are conducted against the current rate availability snapshot for the requested stay dates. Adding rate_availability_id links the group evaluation to the specific rate availability re',
    `revenue_rate_plan_id` BIGINT COMMENT 'Foreign key linking to revenue.revenue_rate_plan. Business justification: Group evaluations are performed for specific rate plans. group_evaluation has rate_plan_code (STRING) which should be normalized to FK. N group_evaluation records â†’ 1 revenue_rate_plan. Removes redund',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Group displacement calculations require the seasonal transient demand baseline (estimated_occupancy_pct, estimated_adr, demand_classification) from seasonal_calendar. Linking group_evaluation to the s',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Group business evaluations are made within the context of the active revenue strategy. The strategy defines minimum acceptable rates, target occupancy, and displacement thresholds that directly inform',
    `ancillary_revenue_estimate` DECIMAL(18,2) COMMENT 'Estimated ancillary revenue from the group including spa, parking, audio-visual, business center, and other non-room, non-F&B spend. Used in total spend calculation for net revenue impact assessment.',
    `arrival_date` DATE COMMENT 'Proposed first night of the group room block. Used as the start of the displacement analysis window in IDeaS G3 RMS.',
    `attrition_pct` DECIMAL(18,2) COMMENT 'Expected attrition percentage for the group block by group type, representing the proportion of contracted rooms the group is expected not to use. Distinct from wash factor in that attrition is the contractual exposure, while wash is the statistical pickup adjustment.',
    `counter_offer_rate` DECIMAL(18,2) COMMENT 'Alternative per-room per-night rate proposed by the revenue manager as a counter-offer to the group organizer when the proposed_group_rate is below the minimum_acceptable_rate. Populated only when revenue_manager_decision = counter_offer.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this group evaluation record was first captured in the Silver Layer lakehouse. Used for data lineage and ETL audit trail.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary amounts in this evaluation record (e.g., USD, EUR, GBP). Ensures consistent financial reporting per USALI and IFRS/GAAP standards.. Valid values are `^[A-Z]{3}$`',
    `cutoff_date` DATE COMMENT 'The date by which unbooked rooms in the group block are released back to general inventory. After this date, the property may sell unreserved block rooms to transient guests. Critical for inventory management and wash factor actualization.',
    `decision_override_reason` STRING COMMENT 'Free-text justification provided by the revenue manager when their decision overrides the RMS recommendation (e.g., strategic account relationship, future business potential, competitive displacement risk). Required when revenue_manager_decision differs from rms_recommendation.',
    `decision_timestamp` TIMESTAMP COMMENT 'Timestamp when the revenue manager recorded their final accept, decline, or counter-offer decision. Used for SLA tracking and decision audit trail.',
    `departure_date` DATE COMMENT 'Proposed last night of the group room block (checkout date). Defines the end of the displacement analysis window.',
    `displacement_cost` DECIMAL(18,2) COMMENT 'Total estimated revenue lost from displaced transient business if the group block is accepted, calculated as transient_rooms_displaced multiplied by transient_adr_displaced across the stay period. Key component of the net revenue impact analysis.',
    `evaluation_status` STRING COMMENT 'Current lifecycle status of the group evaluation workflow. Tracks progression from initial inquiry receipt through revenue manager decision. pending = awaiting RMS analysis; under_review = revenue manager reviewing; recommended_accept = RMS recommends acceptance; recommended_decline = RMS recommends decline; accepted = revenue manager approved; declined = revenue manager rejected.. Valid values are `pending|under_review|recommended_accept|recommended_decline|accepted|declined`',
    `evaluation_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when the group evaluation was initiated and processed by IDeaS G3 RMS. Represents the business event time, distinct from record audit timestamps.',
    `fb_revenue_estimate` DECIMAL(18,2) COMMENT 'Estimated Food and Beverage (F&B) revenue contribution from the group, including banquet, catering, and outlet spend. Sourced from Delphi by Amadeus event catering estimates and historical group F&B spend patterns.',
    `group_name` STRING COMMENT 'Name of the group or event associated with the booking inquiry (e.g., Acme Corp Annual Sales Conference 2025). Used for identification and reporting across Delphi by Amadeus and Oracle OPERA PMS.',
    `group_room_revenue` DECIMAL(18,2) COMMENT 'Total projected room revenue from the group block at the proposed group rate, calculated as adjusted room block (post-wash) multiplied by proposed_group_rate across all nights. Gross revenue contribution from rooms only.',
    `group_type` STRING COMMENT 'Classification of the group by business segment. Drives wash factor parameters and attrition modeling in IDeaS G3 RMS. [ENUM-REF-CANDIDATE: corporate|association|government|leisure|sports|wedding|social|tour_operator|incentive â€” promote to reference product]',
    `historical_wash_pct` DECIMAL(18,2) COMMENT 'Historical average wash percentage for this group type and property, derived from past group performance data in IDeaS G3 RMS. Serves as the baseline input before adjustments for lead time and current demand conditions.',
    `inquiry_reference_number` STRING COMMENT 'Externally-known alphanumeric reference number assigned to the group booking inquiry, as generated by the Central Reservation System (CRS) or Property Management System (PMS). Used to cross-reference the evaluation with the originating inquiry across Oracle OPERA PMS and Sabre SynXis CRS.',
    `is_definite_booking` BOOLEAN COMMENT 'Indicates whether the group inquiry has converted to a definite (contracted) booking following a positive revenue manager decision. True = definite booking confirmed; False = still in tentative or evaluation stage.',
    `lead_time_bucket` STRING COMMENT 'Categorical bucket representing the number of days between the group inquiry date and the proposed arrival date. Used as a parameter in wash factor modeling, as groups booked further in advance typically exhibit higher wash rates.. Valid values are `0_30_days|31_90_days|91_180_days|181_365_days|over_365_days`',
    `los_nights` STRING COMMENT 'Total number of nights in the proposed group stay, calculated as departure_date minus arrival_date. Represents the Length of Stay (LOS) for the group block used in displacement and revenue impact modeling.',
    `minimum_acceptable_rate` DECIMAL(18,2) COMMENT 'The minimum per-room per-night rate recommended by IDeaS G3 RMS below which accepting the group would result in negative net revenue impact after accounting for displacement costs. This is the RMS-generated floor rate for negotiation.',
    `net_revenue_impact` DECIMAL(18,2) COMMENT 'Net revenue impact of accepting the group, calculated as total group spend (room + F&B + ancillary) minus displacement cost. Positive value indicates the group is accretive; negative value indicates the group destroys revenue versus transient alternative. Primary decision metric in the evaluation.',
    `peak_night_rooms` STRING COMMENT 'Maximum number of rooms occupied on any single night within the group block. Used for capacity planning and displacement analysis at the peak demand point.',
    `proposed_group_rate` DECIMAL(18,2) COMMENT 'The per-room per-night rate proposed by the group organizer or sales manager for the room block, expressed in the propertys operating currency. This is the rate under evaluation against the displacement cost and minimum acceptable rate.',
    `revenue_manager_decision` STRING COMMENT 'Final decision made by the revenue manager after reviewing the RMS recommendation and displacement analysis. May align with or override the RMS recommendation. pending indicates no decision has been recorded yet.. Valid values are `accept|decline|counter_offer|pending`',
    `revpar_impact` DECIMAL(18,2) COMMENT 'Estimated change in Revenue Per Available Room (RevPAR) for the property during the group stay dates if the group is accepted, compared to the transient-only forecast. Negative RevPAR impact is a key indicator for decline recommendation.',
    `rgi_benchmark` DECIMAL(18,2) COMMENT 'The propertys Revenue Generation Index (RGI) from the STR STAR Report for the competitive set during the evaluation period. Used as a competitive context benchmark to assess whether accepting the group at the proposed rate is competitively rational.',
    `rms_recommendation` STRING COMMENT 'Automated accept, decline, or counter-offer recommendation generated by IDeaS G3 RMS based on displacement analysis, wash factor modeling, and net revenue impact. This is the system-generated recommendation prior to revenue manager override.. Valid values are `accept|decline|counter_offer`',
    `room_block_size` STRING COMMENT 'Total number of guest rooms requested in the group block across all nights of the stay. This is the peak or contracted room block size as submitted in the group inquiry.',
    `source_system_code` STRING COMMENT 'The native record identifier from the originating operational system (IDeaS G3 RMS group evaluation ID or Delphi by Amadeus opportunity ID). Enables traceability back to the system of record for audit and reconciliation purposes.',
    `transient_adr_displaced` DECIMAL(18,2) COMMENT 'The forecasted Average Daily Rate (ADR) of the transient business that would be displaced by the group block, as estimated by IDeaS G3 RMS. Used to quantify the revenue opportunity cost of accepting the group.',
    `transient_rooms_displaced` STRING COMMENT 'Estimated number of transient (individual) room nights that would be displaced if the group block is accepted, as calculated by IDeaS G3 RMS displacement analysis. Core input to the net revenue impact calculation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp recording when this group evaluation record was last modified in the Silver Layer lakehouse, including revenue manager decision updates or status changes.',
    `wash_factor_pct` DECIMAL(18,2) COMMENT 'The adjusted wash factor percentage applied to the contracted room block to estimate actual pickup. Derived from historical wash percentage, group type attrition patterns, and booking lead time bucket. Expressed as a percentage (e.g., 15.00 = 15% wash). Used to calculate the adjusted room block for revenue modeling.',
    CONSTRAINT pk_group_evaluation PRIMARY KEY(`group_evaluation_id`)
) COMMENT 'Group business evaluation records generated by IDeaS G3 RMS for group booking inquiries, encompassing the full displacement analysis and wash factor modeling. Captures group inquiry reference, proposed dates, room block size, proposed group rate, displacement cost analysis (transient rooms displaced, transient ADR displaced, net revenue impact, total spend including F&B and ancillary), wash factor parameters (expected attrition percentage by group type, booking lead time bucket, historical wash percentage, adjusted wash factor), recommended minimum rate, accept/decline recommendation, evaluation status, and revenue manager decision. This is the SSOT for all group revenue decision-making including displacement modeling and block attrition forecasting.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`pickup_report` (
    `pickup_report_id` BIGINT COMMENT 'Unique surrogate identifier for each pickup report record in the Silver Layer lakehouse. Primary key for this entity. Entity role: TRANSACTION_HEADER â€” represents a discrete revenue management snapshot event tracking booking pace against forecast for a given stay date and property.',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Pickup velocity spikes are frequently driven by loyalty promotions; revenue managers correlate booking pace with active promotions in daily pickup reports. Named process: promotion-driven pickup veloc',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Pickup velocity reports are used to measure whether a marketing campaign is driving booking pace â€” a named revenue management process. Revenue managers monitor pickup reports during campaign flights t',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Pickup reports track booking pace by channel â€” a core revenue management daily process. FK from pickup_report to channel enables channel-level pickup velocity analysis and channel mix optimization dec',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Pickup velocity and booking pace are tracked by cost center for departmental revenue forecasting and operational planning at the department level.',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to revenue.demand_forecast. Business justification: pickup_report tracks reservation pace against forecast for a given stay date. Adding demand_forecast_id links each pickup report to the specific demand forecast it measures pace against. The forecaste',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Pickup velocity reports track room block pickup rates for specific event bookings against cutoff dates. Essential for group pace reporting, attrition risk assessment, and event booking performance mon',
    `event_group_block_id` BIGINT COMMENT 'Foreign key linking to event.event_group_block. Business justification: Pickup reports monitor room pickup velocity against group blocks â€” the event_group_block is the primary source of group room pickup data. Revenue managers use this link to track block-to-pickup ratios',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Pickup reports are used in period-close revenue reconciliation processes. Finance teams require pickup data tagged to fiscal periods for month-end accruals and revenue recognition reporting under USAL',
    `revenue_center_id` BIGINT COMMENT 'Foreign key linking to fnb.revenue_center. Business justification: Revenue managers run F&B pickup reports segmented by revenue center (restaurant vs. bar vs. banquet) to track F&B pace alongside room pickup for total revenue management. The existing monitored_fnb_ou',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Pickup reports track booking pace by market segment. pickup_report has segment_code (STRING) which should be normalized to FK. N pickup_report records â†’ 1 market_segment. Removes redundant segment_cod',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Pickup reports track outlet reservation pace for outlets accepting reservations (fine dining, specialty restaurants). Required for outlet capacity planning, labor scheduling, inventory management alig',
    `property_id` BIGINT COMMENT 'Reference to the property (hotel, resort, or vacation property) for which this pickup report is generated. Links to the property master record in the Property domain.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Foreign key linking to revenue.revenue_rate_plan. Business justification: pickup_report.rate_plan_code (STRING) is a denormalized reference to the rate plan being tracked. Adding revenue_rate_plan_id normalizes this to the authoritative revenue_rate_plan record. rate_plan_c',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Pickup velocity reports are analyzed in the context of seasonal demand periods to assess booking pace relative to seasonal norms. Linking pickup_report to seasonal_calendar enables pace-vs-season benc',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Pickup reports measure booking pace against the revenue strategy targets for a given stay date. Linking pickup_report to strategy enables revenue managers to assess whether pace is on track to meet st',
    `adr_on_books` DECIMAL(18,2) COMMENT 'Average Daily Rate (ADR) of all rooms currently on books for the stay_date as of the report_date. Calculated as total room revenue on books divided by rooms_on_books. Core revenue performance indicator alongside occupancy pace. Expressed in the propertys operating currency.',
    `adr_variance_to_forecast` DECIMAL(18,2) COMMENT 'Difference between adr_on_books and forecasted_adr (adr_on_books minus forecasted_adr). Positive value indicates rate is tracking above forecast; negative value indicates rate is below forecast. Used alongside rooms_variance_to_forecast to assess overall revenue pace.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this pickup report record was first created in the Silver Layer lakehouse. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Satisfies TRANSACTION_HEADER RECORD_AUDIT_CREATED requirement.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values in this pickup report record (adr_on_books, forecasted_adr, revpar_on_books, forecasted_revpar, prior_year_adr, adr_variance_to_forecast). Typically the propertys local operating currency (e.g., USD, EUR, GBP).. Valid values are `^[A-Z]{3}$`',
    `day_of_week` STRING COMMENT 'Day of the week corresponding to the stay_date (e.g., Monday, Friday, Saturday). Critical demand pattern dimension â€” weekday vs weekend demand profiles differ significantly in hospitality, driving different pricing strategies and pace expectations. [ENUM-REF-CANDIDATE: Monday|Tuesday|Wednesday|Thursday|Friday|Saturday|Sunday â€” 7 candidates stripped; promote to reference product]',
    `demand_level` STRING COMMENT 'Revenue management system classification of expected demand intensity for the stay_date as of the report_date. Drives pricing strategy and inventory control decisions: distressed triggers promotional actions; peak triggers rate maximization and LOS (Length of Stay) restrictions.. Valid values are `low|moderate|high|peak|distressed`',
    `forecasted_adr` DECIMAL(18,2) COMMENT 'Revenue management system forecast for the expected ADR (Average Daily Rate) on the stay_date, as generated by IDeaS G3 RMS or Infor EzRMS. Baseline against which adr_on_books is compared to assess rate performance vs plan.',
    `forecasted_revpar` DECIMAL(18,2) COMMENT 'Revenue management system forecast for RevPAR (Revenue Per Available Room) on the stay_date. Baseline against which revpar_on_books is compared to assess overall revenue pace vs plan. Expressed in the propertys operating currency.',
    `forecasted_rooms` STRING COMMENT 'Revenue management system forecast for total rooms expected to be occupied on the stay_date, as generated by IDeaS G3 RMS or Infor EzRMS at the time of this report snapshot. Baseline against which rooms_on_books pace is measured to compute variance.',
    `is_special_event` BOOLEAN COMMENT 'Indicates whether the stay_date coincides with a designated special event (conference, concert, sporting event, holiday, local festival) that materially impacts demand. When true, pace expectations and pricing strategies are adjusted relative to normal demand patterns.',
    `is_weekend` BOOLEAN COMMENT 'Indicates whether the stay_date falls on a weekend (Saturday or Sunday). Boolean flag used to segment pickup reports into weekday vs weekend cohorts for pace analysis, as weekend demand patterns and pricing strategies differ materially from weekday.',
    `lead_time_days` STRING COMMENT 'Number of days between the report_date and the stay_date (stay_date minus report_date). Represents the booking window or days-out at the time of this snapshot. Critical for pace analysis â€” revenue managers compare pickup velocity across standard lead-time intervals (90, 60, 30, 14, 7, 1 days out).',
    `los_restriction_active` BOOLEAN COMMENT 'Indicates whether a LOS (Length of Stay) restriction (minimum stay requirement) is currently active for the stay_date. LOS restrictions are a key revenue management lever applied during high-demand periods to maximize total revenue across multiple nights.',
    `min_los` STRING COMMENT 'Minimum number of nights a guest must stay to book the stay_date, when a LOS restriction is active. Null when los_restriction_active is false. Used to enforce stay-through requirements during high-demand periods to prevent short-stay displacement of longer, higher-value bookings.',
    `notes` STRING COMMENT 'Free-text annotations entered by the revenue manager to document observations, strategy decisions, or contextual factors affecting the pickup pace for this stay_date (e.g., Rate opened on OTA due to slow pace, Group block released â€” expect transient pickup). Supports audit trail and strategy documentation.',
    `pickup_velocity` DECIMAL(18,2) COMMENT 'Rate of new reservations being added per day for the stay_date, calculated as the incremental rooms picked up divided by the number of days elapsed in the measurement window. Expressed as rooms per day. Enables revenue managers to assess acceleration or deceleration of booking pace.',
    `prior_year_adr` DECIMAL(18,2) COMMENT 'ADR (Average Daily Rate) on books for the equivalent stay_date in the prior year, at the same lead time. Enables year-over-year rate comparison to assess whether current pricing strategy is yielding rate improvement or erosion versus the prior period.',
    `prior_year_rooms_on_books` STRING COMMENT 'Number of rooms that were on books for the equivalent stay_date in the prior year, at the same lead time (days out). Enables year-over-year (YOY) pace comparison â€” a standard revenue management benchmarking technique to contextualize current booking pace against historical performance.',
    `report_date` DATE COMMENT 'The calendar date on which this pickup snapshot was captured. Represents the as-of date for all rooms-on-books and ADR figures in this record. The difference between stay_date and report_date defines the lead time (days out). Satisfies TRANSACTION_HEADER BUSINESS_EVENT_TIMESTAMP requirement (date-precision is standard for daily pickup reports).',
    `report_number` STRING COMMENT 'Externally-known business identifier for this pickup report record, typically formatted as PKP-{PropertyCode}-{StayDate}-{SequenceNumber}. Used by revenue managers to reference specific pickup snapshots in IDeaS G3 RMS and Infor EzRMS reporting. Satisfies TRANSACTION_HEADER BUSINESS_IDENTIFIER requirement.. Valid values are `^PKP-[A-Z0-9]{3,10}-[0-9]{8}-[0-9]{6}$`',
    `report_status` STRING COMMENT 'Current lifecycle state of this pickup report record. draft indicates the snapshot is being assembled; published indicates it is available for revenue manager consumption; superseded indicates a later snapshot for the same stay_date/report_date exists; cancelled indicates the report was voided. Satisfies TRANSACTION_HEADER LIFECYCLE_STATUS requirement.. Valid values are `draft|published|superseded|cancelled`',
    `report_type` STRING COMMENT 'Classification of the pickup report generation cadence: daily for standard automated daily snapshots, weekly for weekly pace summaries, monthly for month-end pace reviews, or adhoc for analyst-triggered on-demand reports. Determines the reporting frequency context for pace trend analysis.. Valid values are `daily|weekly|monthly|adhoc`',
    `revpar_on_books` DECIMAL(18,2) COMMENT 'Revenue Per Available Room (RevPAR) derived from current on-books position, calculated as (adr_on_books multiplied by rooms_on_books) divided by total_available_rooms. Composite pace metric combining rate and occupancy performance. Expressed in the propertys operating currency.',
    `room_type_code` STRING COMMENT 'Room type classification for which this pickup report is scoped (e.g., STD, DLX, STE, KNG, DBL). When null, the report covers all room types for the property. Enables room-type-level pace analysis to support inventory controls and upsell strategy.',
    `rooms_on_books` STRING COMMENT 'Total number of rooms confirmed on books for the stay_date as of the report_date. This is the primary pace indicator â€” the current committed inventory position. Revenue managers compare this against forecast and prior-year actuals to assess demand trajectory.',
    `rooms_on_books_14d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 14 days (i.e., the snapshot captured 14 days prior to stay_date). Critical short-window pace indicator used to trigger last-minute pricing tactics and inventory controls.',
    `rooms_on_books_1d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 1 day (i.e., the snapshot captured 1 day prior to stay_date). Final pre-arrival pace indicator representing near-final committed occupancy before day-of walk-ins.',
    `rooms_on_books_30d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 30 days (i.e., the snapshot captured 30 days prior to stay_date). Key pace benchmark for near-term demand assessment and rate strategy adjustments.',
    `rooms_on_books_60d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 60 days (i.e., the snapshot captured 60 days prior to stay_date). Standard pace benchmark used by revenue managers to assess mid-range booking momentum.',
    `rooms_on_books_7d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 7 days (i.e., the snapshot captured 7 days prior to stay_date). Near-arrival pace indicator used to assess last-week demand and trigger promotional or restriction actions.',
    `rooms_on_books_90d` STRING COMMENT 'Number of rooms that were on books for the stay_date when the lead time was 90 days (i.e., the snapshot captured 90 days prior to stay_date). Used as a historical pace benchmark for comparison against current rooms_on_books to measure pickup velocity over the 90-day window.',
    `rooms_variance_to_forecast` STRING COMMENT 'Difference between rooms_on_books and forecasted_rooms (rooms_on_books minus forecasted_rooms). Positive value indicates ahead-of-pace (over-performing vs forecast); negative value indicates behind-pace (under-performing). Primary KPI for revenue manager intervention decisions.',
    `source_system` STRING COMMENT 'Operational system of record from which this pickup report data was sourced (IDeaS_G3_RMS, Infor_EzRMS, OPERA_PMS, or Manual for analyst-entered overrides). Enables data lineage tracking and source-system reconciliation in the Silver Layer lakehouse.. Valid values are `IDeaS_G3_RMS|Infor_EzRMS|OPERA_PMS|Manual`',
    `special_event_name` STRING COMMENT 'Name or description of the special event associated with the stay_date when is_special_event is true (e.g., Super Bowl Weekend, Annual Tech Conference, New Years Eve). Provides context for anomalous pace patterns in revenue management reporting.',
    `stay_date` DATE COMMENT 'The specific calendar date for which booking pace and pickup velocity are being measured. This is the future arrival/occupancy date that revenue managers are monitoring. Central dimension of the pickup report â€” all rooms-on-books and ADR snapshots relate to this date.',
    `total_available_rooms` STRING COMMENT 'Total number of rooms available for sale for the stay_date at the property (net of out-of-order and out-of-service rooms). Denominator for occupancy rate (OCC) calculation and RevPAR computation. Sourced from Oracle OPERA PMS inventory controls.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this pickup report record was last modified in the Silver Layer lakehouse. Formatted as yyyy-MM-ddTHH:mm:ss.SSSXXX. Satisfies TRANSACTION_HEADER RECORD_AUDIT_UPDATED requirement.',
    CONSTRAINT pk_pickup_report PRIMARY KEY(`pickup_report_id`)
) COMMENT 'Reservation pickup tracking records measuring the pace of bookings against forecast for a given stay date and property. Captures stay date, report date, rooms on books at various lead-time snapshots (90-day, 60-day, 30-day, 14-day, 7-day, 1-day), ADR on books, RevPAR on books, pickup velocity, and variance to forecast. Critical for revenue managers to assess booking pace and adjust pricing strategy.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`negotiated_rate` (
    `negotiated_rate_id` BIGINT COMMENT 'Unique surrogate identifier for the negotiated rate agreement record in the lakehouse Silver layer. Primary key for this entity.',
    `account_id` BIGINT COMMENT 'Foreign key linking to event.event_account. Business justification: Negotiated rates are contracted with specific event accounts (corporate, consortia, national accounts). Essential for contract rate management, event planner rate loading, and account-specific pricing',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Negotiated corporate rates are sometimes created as part of B2B marketing campaigns. Tracking the originating campaign supports contract performance analysis and measures campaign success in driving c',
    `campaign_offer_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign_offer. Business justification: Negotiated rates are sometimes tied to specific campaign offers (e.g., consortia rates bundled with a promotional offer). Rate loading process requires referencing the campaign offer for offer code va',
    `corporate_account_id` BIGINT COMMENT 'Foreign key linking to guest.corporate_account. Business justification: Contract management and rate loading: revenue managers must link negotiated rates to the guest corporate account to validate credit limits, billing instructions, and contracted room-night commitments ',
    `channel_id` BIGINT COMMENT 'Foreign key linking to channel.channel. Business justification: Corporate negotiated rates are loaded to specific channels (GDS with specific chain codes, OTA corporate programs, direct booking engines). Rate loading and distribution tracking requires knowing whic',
    `event_booking_id` BIGINT COMMENT 'Foreign key linking to event.event_booking. Business justification: Bespoke negotiated rates are frequently created for a single large event booking (e.g., a corporate conference). Linking the negotiated rate to the specific event booking enables rate loading validati',
    `event_contract_id` BIGINT COMMENT 'Foreign key linking to event.event_contract. Business justification: Negotiated rates are formalized and referenced in event contracts. Linking the negotiated rate record to the event contract enables contract compliance auditing, rate loading verification against cont',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Corporate and consortia negotiated rates are loaded and audited by fiscal year for rate parity compliance, commission reconciliation, and financial reporting. Finance teams require fiscal period taggi',
    `franchise_agreement_id` BIGINT COMMENT 'Foreign key linking to property.franchise_agreement. Business justification: Negotiated rates at franchised properties must comply with franchise agreement brand standards, minimum rate requirements, and loyalty fee obligations. Linking revenue_negotiated_rate to franchise_agr',
    `fnb_outlet_id` BIGINT COMMENT 'Foreign key linking to fnb.fnb_outlet. Business justification: Corporate negotiated rates include outlet benefits (breakfast at specific outlet, lounge access). Required for contract fulfillment, benefit tracking, outlet revenue attribution, guest entitlement ver',
    `menu_id` BIGINT COMMENT 'Foreign key linking to fnb.menu. Business justification: Corporate and consortia negotiated rate contracts that include F&B (e.g., breakfast-inclusive corporate rates) specify the exact menu included. This is a contractual element â€” rate loading in the CRS/',
    `ledger_id` BIGINT COMMENT 'Foreign key linking to finance.ledger. Business justification: Negotiated corporate rates post to specific GL accounts for contract revenue tracking, corporate account profitability analysis, and revenue recognition compliance.',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: Negotiated rates are classified by market segment (e.g., Corporate, Wholesale). revenue_negotiated_rate has market_segment_code (STRING) which should be normalized to FK. N negotiated_rate records â†’ 1',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Corporate negotiated rates often include tier-based eligibility or enhanced benefits. Business process: enforcing tier requirements for corporate rate access, common in negotiated contracts that offer',
    `program_id` BIGINT COMMENT 'Foreign key linking to experience.program. Business justification: Corporate negotiated rates frequently bundle specific experience programs (e.g., executive lounge access, welcome amenity). Linking negotiated rates to experience programs enables contract compliance ',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Negotiated corporate rates are sometimes bundled with loyalty promotions (e.g., bonus points for corporate travelers on negotiated rates). Named process: promotion-enhanced negotiated rate configurati',
    `property_id` BIGINT COMMENT 'Reference to the property for which this negotiated rate agreement applies. A single negotiated rate may be scoped to one property or replicated per property for multi-property contracts.',
    `revenue_rate_plan_id` BIGINT COMMENT 'Reference to the parent rate plan definition under which this negotiated rate is structured. Links to the rate plan master in Sabre SynXis CRS or Oracle OPERA PMS.',
    `room_type_id` BIGINT COMMENT 'Reference to the specific room type to which this negotiated rate applies. Null if the rate applies to all room types under the agreement.',
    `strategy_id` BIGINT COMMENT 'Foreign key linking to revenue.strategy. Business justification: Negotiated rate agreements are established within the context of the revenue strategy (e.g., LRA rates, corporate rates aligned to strategy targets). Adding strategy_id links each negotiated rate to t',
    `travel_agent_id` BIGINT COMMENT 'Foreign key linking to reservation.travel_agent. Business justification: Negotiated rates are contracted with specific travel agents. Linking revenue_negotiated_rate to travel_agent enables rate loading verification, commission reconciliation, and contract management. reve',
    `advance_booking_days` STRING COMMENT 'Minimum number of days in advance a reservation must be made to qualify for this negotiated rate. Zero indicates same-day booking is permitted.',
    `amount` DECIMAL(18,2) COMMENT 'The contracted nightly room rate (Average Daily Rate) agreed upon for this account. Represents the fixed or base rate per room per night in the specified currency. Core pricing field for revenue management and contract compliance.',
    `approval_status` STRING COMMENT 'Approval workflow status for this negotiated rate agreement. Rates must be approved by revenue management leadership before loading into CRS/GDS channels.. Valid values are `approved|pending_approval|rejected|under_review`',
    `approved_by` STRING COMMENT 'Name or employee identifier of the revenue management leader or director who approved this negotiated rate agreement for distribution.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate agreement received final approval for loading and distribution.',
    `blackout_dates` STRING COMMENT 'Comma-separated list or date range expressions representing dates on which this negotiated rate is not available (e.g., peak demand periods, holidays, special events). Stored as a structured string; detailed blackout records are managed in the rate_restriction product.',
    `breakfast_included` BOOLEAN COMMENT 'Indicates whether breakfast is included in the negotiated rate. Affects F&B (Food and Beverage) revenue allocation and rate value proposition reporting.',
    `commission_pct` DECIMAL(18,2) COMMENT 'Commission percentage payable to the TMC, travel agency, or consortia for reservations booked under this negotiated rate. Expressed as a percentage of the negotiated rate amount.',
    `committed_room_nights` STRING COMMENT 'Total number of room nights the account has committed to book under this negotiated rate agreement for the contract period. Basis for volume discount qualification and contract performance tracking.',
    `consortia_code` STRING COMMENT 'Identifier for the travel consortia (e.g., Virtuoso, Signature, Ensemble, Internova) under which this negotiated rate is offered. Null for direct corporate accounts not affiliated with a consortia.',
    `contract_end_date` DATE COMMENT 'The date on which the negotiated rate agreement expires and the rate is no longer available for booking. Null for open-ended agreements. Aligns with the MASTER_AGREEMENT EFFECTIVE_UNTIL category.',
    `contract_reference_number` STRING COMMENT 'External contract or agreement reference number assigned by the account, TMC, or legal department. Used for contract management, audit, and dispute resolution.',
    `contract_start_date` DATE COMMENT 'The date from which the negotiated rate agreement becomes contractually binding and the rate is available for booking. Aligns with the MASTER_AGREEMENT EFFECTIVE_FROM category.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate record was first created in the source system. Supports audit trail, data lineage, and GDPR/CCPA data lifecycle management.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code in which the negotiated rate amount is denominated (e.g., USD, EUR, GBP). Required for multi-currency property portfolios.. Valid values are `^[A-Z]{3}$`',
    `gds_chain_code` STRING COMMENT 'Two-letter GDS chain code used to identify the hotel brand/chain in Sabre, Amadeus, Galileo, and Worldspan for rate loading and distribution of this negotiated rate.. Valid values are `^[A-Z]{2}$`',
    `iata_number` STRING COMMENT 'IATA-assigned numeric identifier for the Travel Management Company (TMC) or travel agency associated with this negotiated rate. Used for commission tracking and GDS rate access validation.. Valid values are `^[0-9]{7,8}$`',
    `is_lra` BOOLEAN COMMENT 'Indicates whether this negotiated rate carries a Last Room Availability (LRA) obligation, requiring the property to honor the contracted rate as long as any room of the applicable type remains available, regardless of demand or yield management controls.',
    `is_non_refundable` BOOLEAN COMMENT 'Indicates whether reservations booked under this negotiated rate are non-refundable (NRR). Affects cancellation policy enforcement and revenue recognition timing.',
    `max_los` STRING COMMENT 'Maximum number of consecutive nights allowed per reservation under this negotiated rate. Null if no upper limit is imposed.',
    `min_los` STRING COMMENT 'Minimum number of consecutive nights required per reservation to qualify for this negotiated rate. Enforced at booking in Sabre SynXis CRS and Oracle OPERA PMS.',
    `min_night_commitment` STRING COMMENT 'Minimum number of room nights the account is contractually committed to consume during the contract period. Used for volume tracking and contract compliance reporting.',
    `negotiation_owner` STRING COMMENT 'Name or employee identifier of the revenue manager or sales manager responsible for negotiating and managing this rate agreement. Used for accountability and performance tracking.',
    `rate_bar_variance_pct` DECIMAL(18,2) COMMENT 'The percentage discount or premium of this negotiated rate relative to the Best Available Rate (BAR) at time of contract negotiation. Used by revenue management to assess rate competitiveness and yield impact.',
    `rate_code` STRING COMMENT 'Alphanumeric rate code used to identify and load this negotiated rate in Sabre SynXis CRS and Oracle OPERA PMS. This is the externally-known business identifier referenced in GDS/CRS rate loading and reservation transactions.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `rate_includes_tax` BOOLEAN COMMENT 'Indicates whether the negotiated rate amount is inclusive of applicable taxes. Critical for revenue recognition, financial reporting, and guest billing accuracy.',
    `rate_loaded_timestamp` TIMESTAMP COMMENT 'Date and time when the negotiated rate was successfully loaded into Sabre SynXis CRS and/or Oracle OPERA PMS for distribution. Null if loading has not yet occurred.',
    `rate_loading_status` STRING COMMENT 'Current status of the rate loading process in Sabre SynXis CRS and Oracle OPERA PMS. Indicates whether the negotiated rate has been successfully distributed to all applicable booking channels.. Valid values are `loaded|pending|failed|not_loaded|deactivated`',
    `rate_name` STRING COMMENT 'Human-readable name describing the negotiated rate agreement, typically referencing the account or program name (e.g., Acme Corp 2025 Corporate Rate). Used in reporting and rate management dashboards.',
    `rate_status` STRING COMMENT 'Current lifecycle status of the negotiated rate agreement. Controls whether the rate is bookable and distributed through CRS/GDS channels.. Valid values are `active|inactive|pending|suspended|expired|draft`',
    `rate_type` STRING COMMENT 'Classification of the pricing structure for this negotiated rate. Fixed rates are static for the contract period; dynamic rates may fluctuate within agreed bounds; tiered rates vary by volume; per diem rates are government-mandated ceiling rates.. Valid values are `fixed|dynamic|tiered|per_diem`',
    `source_system` STRING COMMENT 'Operational system of record from which this negotiated rate record originated. Supports data lineage tracking and reconciliation across Oracle OPERA PMS, Sabre SynXis CRS, and Salesforce CRM.. Valid values are `OPERA_PMS|SYNXIS_CRS|SALESFORCE_CRM|IDEASG3_RMS|MANUAL`',
    `source_system_rate_reference` STRING COMMENT 'Native identifier of this negotiated rate record in the originating operational system (Oracle OPERA PMS, Sabre SynXis CRS, or Salesforce CRM). Enables traceability and reconciliation between the lakehouse and source systems.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this negotiated rate record was last modified in the source system. Supports change tracking, audit compliance, and incremental ETL processing.',
    CONSTRAINT pk_negotiated_rate PRIMARY KEY(`negotiated_rate_id`)
) COMMENT 'Corporate and wholesale negotiated rate agreements defining contracted pricing for specific accounts, travel management companies (TMCs), and consortia. Captures account identifier, rate code, negotiated rate amount, LRA (Last Room Availability) obligation, blackout dates, minimum night commitment, contract period, and rate loading status in Sabre SynXis CRS and Oracle OPERA PMS. Distinct from public rate plans â€” these are account-specific contracted rates.';

CREATE OR REPLACE TABLE `travel_hospitality_ecm`.`revenue`.`strategy` (
    `strategy_id` BIGINT COMMENT 'Primary key for strategy',
    `promotion_id` BIGINT COMMENT 'Foreign key linking to loyalty.promotion. Business justification: Revenue strategies are built around loyalty promotion periods (e.g., tier challenge windows, bonus-points weekends). Named process: loyalty-aligned revenue strategy planning. Strategy documents must r',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.finance_budget. Business justification: Revenue strategies are aligned with financial budgets for strategic planning, ensuring revenue tactics support approved financial targets and ownership expectations.',
    `campaign_id` BIGINT COMMENT 'Foreign key linking to marketing.campaign. Business justification: Revenue strategies often incorporate specific marketing campaigns as tactical levers (e.g., deploy summer family campaign to drive weekend occupancy). Strategy owners need this link for execution trac',
    `competitive_set_id` BIGINT COMMENT 'Reference to the competitive set definition used for benchmarking this strategy. The competitor set defines the peer properties against which RGI, MPI, and ARI targets are measured via STR STAR Report.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Revenue strategies are implemented at cost center level for tactical execution, departmental accountability, and operational performance management.',
    `demand_forecast_id` BIGINT COMMENT 'Reference to the demand forecast record that informed and underpins this revenue strategy. Links to the revenue.demand_forecast product to provide the analytical basis for strategy targets and tactical decisions.',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Revenue strategies are anchored to fiscal planning periods for budget cycle alignment, target-setting (RevPAR, GOPPAR), and period-close variance reporting. A travel-hospitality revenue manager always',
    `gss_score_id` BIGINT COMMENT 'Foreign key linking to experience.gss_score. Business justification: Revenue strategies explicitly target GSS improvement as a demand driver (experience-driven revenue strategy). Strategic plans link rate positioning to satisfaction goalsâ€”properties pursuing rate growt',
    `hierarchy_id` BIGINT COMMENT 'Foreign key linking to property.hierarchy. Business justification: Revenue strategies are defined at multiple organizational levels (property, region, brand portfolio) aligned with hierarchy nodes. A hierarchy_id on strategy enables regional and portfolio-level prici',
    `hma_contract_id` BIGINT COMMENT 'Foreign key linking to finance.hma_contract. Business justification: Revenue strategies must be calibrated against HMA performance test thresholds and fee structures. Revenue managers reference HMA terms (base fee basis, incentive fee triggers) when setting target RevP',
    `market_segment_id` BIGINT COMMENT 'Foreign key linking to revenue.market_segment. Business justification: strategy.primary_market_segment_focus (STRING) is a denormalized reference to the primary market segment the strategy targets. Adding market_segment_id normalizes this to the authoritative market_segm',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Revenue strategies in full-service hotels are scoped to profit centers (rooms, F&B, spa, events) for GOPPAR and TRevPAR targeting. Finance and revenue management jointly set profit-center-level strate',
    `program_id` BIGINT COMMENT 'Foreign key linking to experience.program. Business justification: Revenue strategies are frequently built around specific guest experience programs (e.g., a luxury package strategy tied to a curated experience program). Linking strategy to program enables revenue im',
    `property_id` BIGINT COMMENT 'Identifier of the hotel or resort property to which this revenue strategy applies. Links to the property master record in Oracle OPERA PMS.',
    `seasonal_calendar_id` BIGINT COMMENT 'Foreign key linking to property.seasonal_calendar. Business justification: Revenue managers build pricing strategies around seasonal demand periods defined in seasonal_calendar (demand_classification, estimated_revpar, blackout dates). Linking strategy to the seasonal period',
    `superseded_by_strategy_id` BIGINT COMMENT 'Reference to the newer revenue strategy record that replaced this one when status is superseded. Enables lineage tracking of strategy evolution and supports audit trail for revenue governance.',
    `tier_id` BIGINT COMMENT 'Foreign key linking to loyalty.tier. Business justification: Revenue strategies are often tier-targeted (e.g., drive Platinum member bookings in shoulder season, protect Gold tier inventory). Named process: tier-targeted revenue strategy planning and execution.',
    `activated_timestamp` TIMESTAMP COMMENT 'Date and time when the strategy status transitioned to active and began governing live pricing and inventory decisions. Distinct from approval timestamp â€” a strategy may be approved in advance and activated at a later point.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the Revenue Director or authorized revenue management leader who formally approved this strategy. Provides governance and audit trail for strategic revenue decisions per SOX internal controls requirements.',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the revenue strategy was formally approved by the authorizing Revenue Director. Establishes the official approval event in the strategy lifecycle for governance and audit trail purposes.',
    `channel_focus` STRING COMMENT 'The primary distribution channel(s) this strategy targets for demand generation (e.g., Direct Web, GDS, OTA, Voice/CRS, Corporate Direct). Informs channel mix optimization and OTA partnership management decisions. Aligns with Sabre SynXis CRS channel codes.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this revenue strategy record was first created in the system. Provides the audit trail creation anchor for the strategy lifecycle.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary target values in this strategy record (e.g., USD, EUR, GBP). Ensures consistent financial reporting across multi-currency property portfolios.. Valid values are `^[A-Z]{3}$`',
    `horizon_type` STRING COMMENT 'Categorizes the temporal scope of the strategy planning horizon. weekly for short-term tactical adjustments, monthly for rolling monthly plans, quarterly for seasonal strategies, annual for full-year budget-aligned strategies, event_based for strategies tied to specific demand events.. Valid values are `weekly|monthly|quarterly|annual|event_based`',
    `inventory_control_approach` STRING COMMENT 'The approved inventory management methodology for this strategy period. open allows all bookings, hurdle_rate applies minimum rate thresholds, length_of_stay (LOS) enforces minimum/maximum stay restrictions, nested uses tiered availability controls, closed restricts availability for specific segments or channels.. Valid values are `open|hurdle_rate|length_of_stay|nested|closed`',
    `key_tactical_actions` STRING COMMENT 'Free-text narrative documenting the specific tactical actions approved as part of this strategy (e.g., Open BAR for all channels on shoulder nights, Apply 5-night minimum LOS restriction over peak weekend, Close OTA channels when occupancy exceeds 85%). Provides governance documentation for revenue decisions.',
    `next_review_date` DATE COMMENT 'The scheduled date for the next formal performance review of this revenue strategy. Drives workflow triggers in the revenue management calendar and ensures timely strategy adjustments based on actual vs. target performance.',
    `notes` STRING COMMENT 'Additional free-text commentary, rationale, or contextual notes provided by the revenue management team regarding this strategy. May include market intelligence, competitive observations, or risk considerations not captured in structured fields.',
    `planning_horizon_end_date` DATE COMMENT 'The last date of the planning period covered by this revenue strategy. Together with planning_horizon_start_date, defines the full strategy window for yield optimization and performance tracking.',
    `planning_horizon_start_date` DATE COMMENT 'The first date of the planning period covered by this revenue strategy. Defines the beginning of the stay-date window over which the strategy governs pricing and inventory decisions.',
    `pricing_approach` STRING COMMENT 'The approved pricing methodology governing rate-setting for this strategy period. bar_based uses Best Available Rate (BAR) as the anchor, dynamic applies algorithmic Dynamic Rate Rules (DRR), fixed uses static rate plans, hybrid combines approaches, competitive_parity aligns rates to competitive set benchmarks.. Valid values are `bar_based|dynamic|fixed|hybrid|competitive_parity`',
    `review_frequency` STRING COMMENT 'The approved cadence at which this strategy is scheduled for performance review and potential revision by the revenue management team. Governs the operational rhythm of the revenue management process.. Valid values are `daily|weekly|bi_weekly|monthly`',
    `rms_strategy_reference_code` STRING COMMENT 'The native strategy or scenario identifier from the source Revenue Management System (IDeaS G3 RMS or Infor EzRMS). Enables traceability back to the originating RMS record for reconciliation and system-of-record alignment.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this strategy record originated. IDeaS_G3_RMS for strategies generated by IDeaS G3, Infor_EzRMS for Infor-sourced strategies, Manual for strategies entered directly by revenue management staff.. Valid values are `IDeaS_G3_RMS|Infor_EzRMS|Manual`',
    `special_event_flag` BOOLEAN COMMENT 'Indicates whether this strategy was created in response to a specific demand-driving special event (e.g., major conference, sporting event, concert, holiday period). When True, the strategy may include event-specific pricing premiums and inventory controls.',
    `special_event_name` STRING COMMENT 'Name of the demand-driving special event associated with this strategy when special_event_flag is True (e.g., Super Bowl LX, Annual Medical Conference, New Year Holiday Period). Provides context for strategy rationale and post-event performance analysis.',
    `strategy_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this revenue strategy record within the Revenue Management System (RMS). Used for cross-system reference and audit trail. Sourced from IDeaS G3 RMS or Infor EzRMS strategy identifiers.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `strategy_name` STRING COMMENT 'Human-readable name describing the revenue strategy (e.g., Q3 2025 Transient Yield Push, Holiday Season Total Revenue Strategy). Used for identification in reporting and governance workflows.',
    `strategy_status` STRING COMMENT 'Current lifecycle state of the revenue strategy record. draft indicates work-in-progress, pending_approval awaits revenue director sign-off, approved is authorized but not yet in effect, active is currently governing pricing decisions, superseded has been replaced by a newer strategy, archived is retained for historical audit.. Valid values are `draft|pending_approval|approved|active|superseded|archived`',
    `strategy_type` STRING COMMENT 'Classification of the revenue strategy by business segment. transient covers individual guest pricing, group covers group block strategies, total_revenue encompasses all revenue streams (TRevPAR focus), food_and_beverage targets F&B revenue optimization, events covers MICE and event revenue. [ENUM-REF-CANDIDATE: transient|group|total_revenue|food_and_beverage|events|loyalty â€” promote to reference product if additional types emerge]. Valid values are `transient|group|total_revenue|food_and_beverage|events`',
    `target_adr` DECIMAL(18,2) COMMENT 'The approved target Average Daily Rate (ADR) in the propertys operating currency for the strategy period. ADR is the primary pricing KPI representing average revenue earned per occupied room per night. Used to benchmark actual ADR performance against strategic intent.',
    `target_ari` DECIMAL(18,2) COMMENT 'The approved target Average Rate Index (ARI) for the strategy period. ARI = Property ADR / Competitive Set ADR. Measures the propertys rate positioning relative to its competitive set. Used alongside MPI and RGI for comprehensive competitive benchmarking.',
    `target_goppar` DECIMAL(18,2) COMMENT 'The approved target Gross Operating Profit Per Available Room (GOPPAR) for the strategy period. GOPPAR incorporates operating costs and provides a profitability-adjusted view of revenue performance, aligned with USALI GOP reporting standards.',
    `target_mpi` DECIMAL(18,2) COMMENT 'The approved target Market Penetration Index (MPI) for the strategy period. MPI = Property Occupancy / Competitive Set Occupancy. Measures the propertys occupancy share relative to its competitive set as defined in STR STAR Report.',
    `target_occupancy_pct` DECIMAL(18,2) COMMENT 'The approved target Occupancy Rate (OCC) expressed as a percentage (0.00â€“100.00) for the strategy period. Represents the proportion of available rooms expected to be sold. Core input to RevPAR calculation and yield optimization decisions.',
    `target_revpar` DECIMAL(18,2) COMMENT 'The approved target Revenue Per Available Room (RevPAR) in the propertys operating currency for the strategy period. RevPAR = ADR Ă— Occupancy Rate. The primary composite KPI for hotel revenue performance and competitive benchmarking via STR STAR Report.',
    `target_rgi` DECIMAL(18,2) COMMENT 'The approved target Revenue Generation Index (RGI) for the strategy period. RGI = Property RevPAR / Competitive Set RevPAR. An RGI above 1.0 indicates the property is outperforming its competitive set. Sourced from STR STAR Report benchmarking data.',
    `target_trevpar` DECIMAL(18,2) COMMENT 'The approved target Total Revenue Per Available Room (TRevPAR) encompassing all revenue streams (rooms, F&B, spa, events, ancillary) per available room for the strategy period. Relevant for total revenue strategies beyond rooms-only yield optimization.',
    `updated_by` STRING COMMENT 'Name or employee identifier of the last person to modify this strategy record. Supports change management and audit trail for revenue governance.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this revenue strategy record was last modified. Tracks the most recent change event for audit trail and data lineage purposes in the Silver Layer lakehouse.',
    `version_number` STRING COMMENT 'Monotonically incrementing version number for this strategy record. Increments each time the strategy is revised and re-approved. Supports audit trail and change management for revenue governance workflows.',
    `created_by` STRING COMMENT 'Name or employee identifier of the revenue management professional who created this strategy record. Supports governance, accountability, and audit trail requirements.',
    CONSTRAINT pk_strategy PRIMARY KEY(`strategy_id`)
) COMMENT 'Revenue strategy records documenting the approved pricing and inventory strategy for a property over a defined planning horizon. Captures strategy period, property, strategy type (transient, group, total revenue), target ADR, target occupancy, target RevPAR, key tactical actions, strategy status (draft, approved, active), and approving revenue director. Provides governance and audit trail for strategic revenue decisions.';

